window.bibleReaderData = window.bibleReaderData || {chapters:{}};
window.bibleReaderData.chapters = window.bibleReaderData.chapters || {};
window.bibleReaderData.chapters['JOB'] = window.bibleReaderData.chapters['JOB'] || {};
(function(chapters){ for (const c in chapters){ window.bibleReaderData.chapters['JOB'][c]=window.bibleReaderData.chapters['JOB'][c]||{}; Object.assign(window.bibleReaderData.chapters['JOB'][c], chapters[c]); } })({"1":{"fa":[{"v":1,"t":"در زمین عوص، مردی بود که ایوب نام داشت و آن مرد کامل و راست و خداترس بود و از بدی اجتناب می‌نمود."},{"v":2,"t":"و برای او، هفت پسر و سه دختر زاییده شدند."},{"v":3,"t":"و اموال او هفت هزار گوسفند و سه هزار شتر و پانصد جفت گاو وپانصد الاغ ماده بود و نوکران بسیار کثیر داشت وآن مرد از تمامی بنی مشرق بزرگتر بود."},{"v":4,"t":"و پسرانش می‌رفتند و در خانه هر یکی ازایشان، در روزش مهمانی می‌کردند و فرستاده، سه خواهر خود را دعوت می‌نمودند تا با ایشان اکل و شرب بنمایند."},{"v":5,"t":"و واقع می‌شد که چون دوره روزهای مهمانی‌ایشان بسر می‌رفت، ایوب فرستاده، ایشان را تقدیس می‌نمود و بامدادان برخاسته، قربانی های سوختنی، به شماره همه ایشان می‌گذرانید، زیرا ایوب می‌گفت: «شایدپسران من گناه کرده، خدا را در دل خود ترک نموده باشند» و ایوب همیشه چنین می‌کرد."},{"v":6,"t":"و روزی واقع شد که پسران خدا آمدند تا به حضور خداوند حاضر شوند و شیطان نیز در میان ایشان آمد."},{"v":7,"t":"و خداوند به شیطان گفت: «از کجاآمدی؟» شیطان در جواب خداوند گفت: «ازتردد کردن در زمین و سیر کردن در آن.»"},{"v":8,"t":"خداوندبه شیطان گفت: «آیا در بنده من ایوب تفکر کردی که مثل او در زمین نیست؟ مرد کامل وراست و خداترس که از گناه اجتناب می‌کند.»"},{"v":9,"t":"شیطان در جواب خداوند گفت: «آیا ایوب مجان از خدا می‌ترسد؟"},{"v":10,"t":"آیا تو گرد او و گردخانه او و گرد همه اموال او، به هر طرف حصارنکشیدی و اعمال دست او را برکت ندادی ومواشی او در زمین منتشر نشد؟"},{"v":11,"t":"لیکن الان دست خود را دراز کن و تمامی مایملک او رالمس نما و پیش روی تو، تو را ترک خواهدنمود.»"},{"v":12,"t":"خداوند به شیطان گفت: «اینک همه اموالش در دست تو است، لیکن دستت را بر خوداو دراز مکن.» پس شیطان از حضور خداوندبیرون رفت."},{"v":13,"t":"و روزی واقع شد که پسران و دخترانش درخانه برادر بزرگ خود می‌خوردند و شراب می‌نوشیدند."},{"v":14,"t":"و رسولی نزد ایوب آمده، گفت: «گاوان شیار می‌کردند و ماده الاغان نزد آنهامی چریدند."},{"v":15,"t":"و سابیان بر آنها حمله آورده، بردند و جوانان را به دم شمشیر کشتند و من به تنهایی رهایی یافتم تا تو را خبر دهم.»"},{"v":16,"t":"و اوهنوز سخن می‌گفت که دیگری آمده، گفت: «آتش خدا از آسمان افتاد و گله و جوانان راسوزانیده، آنها را هلاک ساخت و من به تنهایی رهایی یافتم تا تو را خبر دهم.»"},{"v":17,"t":"و او هنوزسخن می‌گفت که دیگری آمده، گفت: «کلدانیان سه فرقه شدند و بر شتران هجوم آورده، آنها را بردند و جوانان را به دم شمشیر کشتند و من به تنهایی رهایی یافتم تا تو را خبر دهم.»"},{"v":18,"t":"و اوهنوز سخن می‌گفت که دیگری آمده، گفت: «پسران و دخترانت در خانه برادر بزرگ خودمی خوردند و شراب می‌نوشیدند"},{"v":19,"t":"که اینک بادشدیدی از طرف بیابان آمده، چهار گوشه خانه رازد و بر جوانان افتاد که مردند و من به تنهایی رهایی یافتم تا تو را خبر دهم.»"},{"v":20,"t":"آنگاه ایوب برخاسته، جامه خود را درید وسر خود را تراشید و به زمین افتاده، سجده کرد"},{"v":21,"t":"و گفت: «برهنه از رحم مادر خود بیرون آمدم وبرهنه به آنجا خواهم برگشت؛ خداوند داد وخداوند گرفت و نام خداوند متبارک باد.»"},{"v":22,"t":"دراین همه، ایوب گناه نکرد و به خدا جهالت نسبت نداد."}]},"2":{"fa":[{"v":1,"t":"و روزی واقع شد که پسران خدا آمدند تا به حضور خداوند حاضر شوند، و شیطان نیزدر میان ایشان آمد تا به حضور خداوند حاضرشود."},{"v":2,"t":"و خداوند به شیطان گفت: «از کجاآمدی؟» شیطان در جواب خداوند گفت: «ازتردد نمودن در جهان و از سیر کردن در آن.»"},{"v":3,"t":"خداوند به شیطان گفت: «آیا در بنده من ایوب تفکر نمودی که مثل او در زمین نیست؟ مرد کامل و راست و خداترس که از بدی اجتناب می‌نمایدو تا الان کاملیت خود را قایم نگاه می‌دارد، هرچند مرا بر آن واداشتی که او را بی‌سبب اذیت رسانم.»"},{"v":4,"t":"شیطان در جواب خداوند گفت: «پوست به عوض پوست، و هر‌چه انسان داردبرای جان خود خواهد داد."},{"v":5,"t":"لیکن الان دست خود را دراز کرده، استخوان و گوشت او را لمس نما و تو را پیش روی تو ترک خواهد نمود.»"},{"v":6,"t":"خداوند به شیطان گفت: «اینک او در دست تواست، لیکن جان او را حفظ کن.»"},{"v":7,"t":"پس شیطان از حضور خداوند بیرون رفته، ایوب را از کف پا تا کله‌اش به دملهای سخت مبتلا ساخت."},{"v":8,"t":"و او سفالی گرفت تا خود را با آن بخراشد و در میان خاکستر نشسته بود."},{"v":9,"t":"و زنش او را گفت: «آیا تا بحال کاملیت خود را نگاه می‌داری؟ خدا را ترک کن و بمیر.»"},{"v":10,"t":"او وی را گفت: «مثل یکی از زنان ابله سخن می‌گویی! آیا نیکویی را از خدا بیابیم و بدی رانیابیم؟» در این همه، ایوب به لبهای خود گناه نکرد."},{"v":11,"t":"و چون سه دوست ایوب، این همه بدی راکه بر او واقع شده بود شنیدند، هر یکی از مکان خود، یعنی الیفاز تیمانی و بلدد شوحی و سوفرنعماتی روانه شدند و با یکدیگر همداستان گردیدند که آمده، او را تعزیت گویند و تسلی دهند."},{"v":12,"t":"و چون چشمان خود را از دور بلندکرده، او را نشناختند، آواز خود را بلند نموده، گریستند و هر یک جامه خود را دریده، خاک بسوی آسمان بر سر خود افشاندند."},{"v":13,"t":"و هفت روز و هفت شب همراه او بر زمین نشستند و کسی با وی سخنی نگفت چونکه دیدند که درد او بسیارعظیم است."}]},"3":{"fa":[{"v":1,"t":"و بعد از آن ایوب دهان خود را باز کرده، روز خود را نفرین کرد."},{"v":2,"t":"و ایوب متکلم شده، گفت:"},{"v":3,"t":"«روزی که در آن متولد شدم، هلاک شود و شبی که گفتند مردی در رحم قرار گرفت،"},{"v":4,"t":"آن روز تاریکی شود. و خدا از بالا بر آن اعتنانکند و روشنایی بر او نتابد."},{"v":5,"t":"تاریکی و سایه موت، آن را به تصرف آورند. ابر بر آن ساکن شود. کسوفات روز آن را بترساند."},{"v":6,"t":"و آن شب را ظلمت غلیظ فرو‌گیرد و در میان روزهای سال شادی نکند، و به شماره ماهها داخل نشود."},{"v":7,"t":"اینک آن شب نازاد باشد. و آواز شادمانی در آن شنیده نشود."},{"v":8,"t":"لعنت کنندگان روز، آن را نفرین نمایند، که در برانگیزانیدن لویاتان ماهر می‌باشند."},{"v":9,"t":"ستارگان شفق آن، تاریک گردد و انتظار نوربکشد و نباشد، و مژگان سحر را نبیند،"},{"v":10,"t":"چونکه درهای رحم مادرم را نبست، و مشقت را ازچشمانم مستور نساخت."},{"v":11,"t":"«چرا از رحم مادرم نمردم؟ و چون از شکم بیرون آمدم چرا جان ندادم؟"},{"v":12,"t":"چرا زانوها مراقبول کردند، و پستانها تا مکیدم؟"},{"v":13,"t":"زیرا تا بحال می‌خوابیدم و آرام می‌شدم. در خواب می‌بودم واستراحت می‌یافتم."},{"v":14,"t":"با پادشاهان و مشیران جهان، که خرابه‌ها برای خویشتن بنا نمودند،"},{"v":15,"t":"یابا سروران که طلا داشتند، و خانه های خود را ازنقره پر ساختند."},{"v":16,"t":"یا مثل سقط پنهان شده نیست می‌بودم، مثل بچه هایی که روشنایی را ندیدند."},{"v":17,"t":"در آنجا شریران از شورش باز می‌ایستند، و درآنجا خستگان می‌آرامند،"},{"v":18,"t":"در آنجا اسیران دراطمینان با هم ساکنند، و آواز کارگذاران رانمی شنوند."},{"v":19,"t":"کوچک و بزرگ در آنجا یک‌اند. وغلام از آقایش آزاد است."},{"v":20,"t":"چرا روشنی به مستمند داده شود؟ و زندگی به تلخ جانان؟"},{"v":21,"t":"که انتظار موت را می‌کشند و یافت نمی شود، و برای آن حفره می‌زنند بیشتر از گنجها."},{"v":22,"t":"که شادی وابتهاج می‌نمایند و مسرور می‌شوند چون قبر رامی یابند؟"},{"v":23,"t":"چرا نور داده می‌شود به کسی‌که راهش مستور است، که خدا اطرافش را مستورساخته است؟"},{"v":24,"t":"زیرا که ناله من، پیش از خوراکم می‌آید و نعره من، مثل آب ریخته می‌شود،"},{"v":25,"t":"زیرا ترسی که از آن می‌ترسیدم، بر من واقع شد. و آنچه از آن بیم داشتم بر من رسید."},{"v":26,"t":"مطمئن و آرام نبودم و راحت نداشتم وپریشانی بر من آمد.»"}]},"4":{"fa":[{"v":1,"t":"و الیفاز تیمانی در جواب گفت:"},{"v":2,"t":"«اگر کسی جرات کرده، با تو سخن گوید، آیا تورا ناپسند می‌آید؟ لیکن کیست که بتواند از سخن‌گفتن بازایستد؟"},{"v":3,"t":"اینک بسیاری را ادب آموخته‌ای و دستهای ضعیف را تقویت داده‌ای."},{"v":4,"t":"سخنان تو لغزنده را قایم داشت، و تو زانوهای لرزنده را تقویت دادی."},{"v":5,"t":"لیکن الان به تو رسیده است و ملول شده‌ای، تو را لمس کرده است وپریشان گشته‌ای."},{"v":6,"t":"آیا توکل تو بر تقوای تونیست؟ و امید تو بر کاملیت رفتار تو نی؟"},{"v":7,"t":"الان فکر کن! کیست که بی‌گناه هلاک شد؟ و راستان درکجا تلف شدند؟"},{"v":8,"t":"چنانکه من دیدم آنانی که شرارت را شیار می‌کنند و شقاوت را می‌کارندهمان را می‌دروند."},{"v":9,"t":"از نفخه خدا هلاک می‌شوندو از باد غضب او تباه می‌گردند."},{"v":10,"t":"غرش شیر ونعره سبع و دندان شیربچه‌ها شکسته می‌شود."},{"v":11,"t":"شیر نر از نابودن شکار هلاک می‌شود وبچه های شیر ماده پراکنده می‌گردند."},{"v":12,"t":"«سخنی به من در خفا رسید، و گوش من آواز نرمی از آن احساس نمود."},{"v":13,"t":"در تفکرها ازرویاهای شب، هنگامی که خواب سنگین بر مردم غالب شود،"},{"v":14,"t":"خوف و لرز بر من مستولی شد که جمیع استخوانهایم را به جنبش آورد."},{"v":15,"t":"آنگاه روحی از پیش روی من گذشت، و مویهای بدنم برخاست."},{"v":16,"t":"در آنجا ایستاد، اما سیمایش راتشخیص ننمودم. صورتی در‌پیش نظرم بود. خاموشی بود و آوازی شنیدم"},{"v":17,"t":"که آیا انسان به حضور خدا عادل شمرده شود؟ و آیا مرد در نظرخالق خود طاهر باشد؟"},{"v":18,"t":"اینک بر خادمان خوداعتماد ندارد، و به فرشتگان خویش، حماقت نسبت می‌دهد."},{"v":19,"t":"پس چند مرتبه زیاده به ساکنان خانه های گلین، که اساس ایشان در غبار است، که مثل بید فشرده می‌شوند!"},{"v":20,"t":"از صبح تا شام خردمی شوند، تا به ابد هلاک می‌شوند و کسی آن را به‌خاطر نمی آورد."},{"v":21,"t":"آیا طناب خیمه ایشان ازایشان کنده نمی شود؟ پس بدون حکمت می‌میرند."}]},"5":{"fa":[{"v":1,"t":"«الان استغاثه کن و آیا کسی هست که تو راجواب دهد؟ و به کدامیک از مقدسان توجه خواهی نمود؟"},{"v":2,"t":"زیرا غصه، احمق رامی کشد و حسد، ابله را می‌میراند."},{"v":3,"t":"من احمق رادیدم که ریشه می‌گرفت و ناگهان مسکن او رانفرین کردم."},{"v":4,"t":"فرزندان او از امنیت دور هستند ودر دروازه پایمال می‌شوند و رهاننده‌ای نیست."},{"v":5,"t":"که گرسنگان محصول او را می‌خورند، و آن رانیز از میان خارها می‌چینند، و دهان تله برای دولت ایشان باز است."},{"v":6,"t":"زیرا که بلا از غبار درنمی آید، و مشقت از زمین نمی روید."},{"v":7,"t":"بلکه انسان برای مشقت مولود می‌شود، چنانکه شراره‌ها بالامی پرد."},{"v":8,"t":"و لکن من نزد خدا طلب می‌کردم، ودعوی خود را بر خدا می‌سپردم،"},{"v":9,"t":"که اعمال عظیم و بی‌قیاس می‌کند و عجایب بی‌شمار؛"},{"v":10,"t":"که بر روی زمین باران می‌باراند، و آب بر روی صخره‌ها جاری می‌سازد،"},{"v":11,"t":"تا مسکینان را به مقام بلند برساند، و ماتمیان به سلامتی سرافراشته شوند."},{"v":12,"t":"که فکرهای حیله گران را باطل می‌سازد، به طوری که دستهای ایشان هیچ کار مفیدنمی تواند کرد."},{"v":13,"t":"که حکیمان را در حیله ایشان گرفتار می‌سازد، و مشورت مکاران مشوش می‌شود."},{"v":14,"t":"در روز به تاریکی برمی خورند و به وقت ظهر، مثل شب کورانه راه می‌روند."},{"v":15,"t":"که مسکین را از شمشیر دهان ایشان، و از دست زورآور نجات می‌دهد."},{"v":16,"t":"پس امید، برای ذلیل پیدا می‌شود و شرارت دهان خود را می‌بندد."},{"v":17,"t":"«هان، خوشابحال شخصی که خدا تنبیهش می‌کند. پس تادیب قادر مطلق را خوار مشمار."},{"v":18,"t":"زیرا که او مجروح می‌سازد و التیام می‌دهد، ومی کوبد و دست او شفا می‌دهد."},{"v":19,"t":"در شش بلا، تو را نجات خواهد داد و در هفت بلا، هیچ ضرر برتو نخواهد رسید."},{"v":20,"t":"در قحط تو را از موت فدیه خواهد داد، و در جنگ از دم شمشیر."},{"v":21,"t":"ازتازیانه زبان پنهان خواهی ماند، و چون هلاکت آید، از آن نخواهی ترسید."},{"v":22,"t":"بر خرابی وتنگسالی خواهی خندید، و از وحوش زمین بیم نخواهی داشت."},{"v":23,"t":"زیرا با سنگهای صحراهمداستان خواهی بود، و وحوش صحرا با توصلح خواهند کرد."},{"v":24,"t":"و خواهی دانست که خیمه تو ایمن است، و مسکن خود را تجسس خواهی کرد و چیزی مفقود نخواهی یافت."},{"v":25,"t":"وخواهی دانست که ذریتت کثیر است و اولاد تومثل علف زمین."},{"v":26,"t":"و در شیخوخیت به قبرخواهی رفت، مثل بافه گندم که در موسمش برداشته می‌شود."},{"v":27,"t":"اینک این را تفتیش نمودیم وچنین است، پس تو این را بشنو و برای خویشتن بدان.»"}]},"6":{"fa":[{"v":1,"t":"و ایوب جواب داده، گفت:"},{"v":2,"t":"«کاش که غصه من سنجیده شود. و مشقت مرا درمیزان با آن بگذارند."},{"v":3,"t":"زیرا که الان از ریگ دریاسنگینتر است. از این سبب سخنان من بیهوده می‌باشد."},{"v":4,"t":"زیرا تیرهای قادرمطلق در اندرون من است. و روح من زهر آنها را می‌آشامد، و ترسهای خدا بر من صف آرایی می‌کند."},{"v":5,"t":"آیا گورخر باداشتن علف عرعر می‌کند؟ و یا گاو بر آذوقه خودبانگ می‌زند؟"},{"v":6,"t":"آیا چیز بی‌مزه، بی‌نمک خورده می‌شود؟ و یا در سفیده تخم، طعم می‌باشد؟"},{"v":7,"t":"جان من از لمس نمودن آنها کراهت دارد. آنهابرای من مثل خوراک، زشت است."},{"v":8,"t":"«کاش که مسالت من برآورده شود، و خداآرزوی مرا به من بدهد!"},{"v":9,"t":"و خدا راضی شود که مرا خرد کند، و دست خود را بلند کرده، مرامنقطع سازد!"},{"v":10,"t":"آنگاه معهذا مرا تسلی می‌شد ودر عذاب الیم شاد می‌شدم، چونکه کلمات حضرت قدوس را انکار ننمودم."},{"v":11,"t":"من چه قوت دارم که انتظار بکشم و عاقبت من چیست که صبرنمایم؟"},{"v":12,"t":"آیا قوت من قوت سنگها است؟ و یاگوشت من برنج است؟"},{"v":13,"t":"آیا بالکل بی‌اعانت نیستم؟ و مساعدت از من مطرود نشده است؟"},{"v":14,"t":"حق شکسته دل از دوستش ترحم است، اگر‌چه هم ترس قادر مطلق را ترک نماید."},{"v":15,"t":"اما برادران من مثل نهرها مرا فریب دادند، مثل رودخانه وادیها که می‌گذرند."},{"v":16,"t":"که از یخ سیاه فام می‌باشند، و برف در آنها مخفی است."},{"v":17,"t":"وقتی که آب از آنها می‌رود، نابود می‌شوند. و چون گرماشود، از جای خود ناپدید می‌گردند."},{"v":18,"t":"کاروانیان از راه خود منحرف می‌شوند، و در بیابان داخل شده، هلاک می‌گردند."},{"v":19,"t":"کاروانیان تیما به آنهانگران بودند. قافله های سبا امید آن را داشتند."},{"v":20,"t":"از امید خود خجل گردیدند. به آنجا رسیدند وشرمنده گشتند."},{"v":21,"t":"زیرا که الان شما مثل آنهاشده‌اید، مصیبتی دیدید و ترسان گشتید."},{"v":22,"t":"آیاگفتم که چیزی به من ببخشید؟ یا ارمغانی از اموال خود به من بدهید؟"},{"v":23,"t":"یا مرا از دست دشمن رهاکنید؟ و مرا از دست ظالمان فدیه دهید؟"},{"v":24,"t":"«مرا تعلیم دهید و من خاموش خواهم شد، و مرا بفهمانید که در چه چیز خطا کردم."},{"v":25,"t":"سخنان راستی چقدر زورآور است! اما تنبیه شما چه نتیجه می‌بخشد؟"},{"v":26,"t":"آیا گمان می‌برید که سخنان را تنبیه می‌نمایید و سخنان مایوس را که مثل باد است؟"},{"v":27,"t":"یقین برای یتیم قرعه می‌اندازیدو دوست خود را مال تجارت می‌شمارید."},{"v":28,"t":"پس الان التفات کرده، بر من توجه نمایید، و روبه‌روی شما دروغ نخواهم گفت."},{"v":29,"t":"برگردید و بی‌انصافی نباشد، و باز برگردید زیرا عدالت من قایم است."},{"v":30,"t":"آیا در زبان من بی‌انصافی می‌باشد؟ و آیا کام من چیزهای فاسد را تمیز نمی دهد؟"}]},"7":{"fa":[{"v":1,"t":"«آیا برای انسان بر زمین مجاهده‌ای نیست؟ و روزهای وی مثل روزهای مزدور نی؟"},{"v":2,"t":"مثل غلام که برای سایه اشتیاق دارد، و مزدوری که منتظر مزد خویش است،"},{"v":3,"t":"همچنین ماههای بطالت نصیب من شده است، و شبهای مشقت برای من معین گشته."},{"v":4,"t":"چون می‌خوابم می‌گویم: کی برخیزم؟ و شب بگذرد و تا سپیده صبح ازپهلو به پهلو گردیدن خسته می‌شوم."},{"v":5,"t":"جسدم ازکرمها و پاره های خاک ملبس است، و پوستم تراکیده و مقروح می‌شود."},{"v":6,"t":"روزهایم از ماکوی جولا تیزروتر است، و بدون امید تمام می‌شود."},{"v":7,"t":"به یاد آور که زندگی من باد است، و چشمانم دیگر نیکویی را نخواهد دید."},{"v":8,"t":"چشم کسی‌که مرامی بیند دیگر به من نخواهد نگریست، وچشمانت برای من نگاه خواهد کرد و نخواهم بود."},{"v":9,"t":"مثل ابر که پراکنده شده، نابود می‌شود. همچنین کسی‌که به گور فرو می‌رود، برنمی آید."},{"v":10,"t":"به خانه خود دیگر نخواهد برگشت، و مکانش باز او را نخواهد شناخت."},{"v":11,"t":"پس من نیز دهان خود را نخواهم بست. از تنگی روح خود سخن می‌رانم، و از تلخی جانم شکایت خواهم کرد."},{"v":12,"t":"آیا من دریا هستم یا نهنگم که بر من کشیکچی قرار می‌دهی؟"},{"v":13,"t":"چون گفتم که تخت خوابم مراتسلی خواهد داد و بسترم شکایت مرا رفع خواهد کرد،"},{"v":14,"t":"آنگاه مرا به خوابها ترسان گردانیدی، و به رویاها مرا هراسان ساختی."},{"v":15,"t":"به حدی که جانم خفه شدن را اختیار کرد و مرگ رابیشتر از این استخوانهایم."},{"v":16,"t":"کاهیده می‌شوم ونمی خواهم تا به ابد زنده بمانم. مرا ترک کن زیراروزهایم نفسی است."},{"v":17,"t":"«انسان چیست که او را عزت بخشی، و دل خود را با او مشغول سازی؟"},{"v":18,"t":"و هر بامداد از اوتفقد نمایی و هرلحظه او را بیازمایی؟"},{"v":19,"t":"تا به کی چشم خود را از من برنمی گردانی؟ مرا واگذار تاآب دهان خود را فرو برم."},{"v":20,"t":"من گناه کردم، اما با تو‌ای پاسبان بنی آدم چه کنم؟ برای چه مرا به جهت خود هدف ساخته‌ای، به حدی که برای خود بار سنگین شده‌ام؟"},{"v":21,"t":"و چرا گناهم رانمی آمرزی، و خطایم را دور نمی سازی؟ زیرا که الان در خاک خواهم خوابید، و مرا تفحص خواهی کرد و نخواهم بود.»"}]},"8":{"fa":[{"v":1,"t":"پس بلدد شوحی در جواب گفت:"},{"v":2,"t":"«تا به کی این چیزها را خواهی گفت و سخنان دهانت باد شدید خواهد بود؟"},{"v":3,"t":"آیا خداوندداوری را منحرف سازد؟ یا قادر مطلق انصاف رامنحرف نماید؟"},{"v":4,"t":"چون فرزندان تو به او گناه ورزیدند، ایشان را به‌دست عصیان ایشان تسلیم نمود."},{"v":5,"t":"اگر تو به جد و جهد خدا را طلب می‌کردی و نزد قادر مطلق تضرع می‌نمودی،"},{"v":6,"t":"اگر پاک و راست می‌بودی، البته برای تو بیدارمی شد، و مسکن عدالت تو را برخوردارمی ساخت."},{"v":7,"t":"و اگر‌چه ابتدایت صغیر می‌بود، عاقبت تو بسیار رفیع می‌گردید."},{"v":8,"t":"زیرا که ازقرنهای پیشین سوال کن، و به آنچه پدران ایشان تفحص کردند توجه نما،"},{"v":9,"t":"چونکه ما دیروزی هستیم و هیچ نمی دانیم، و روزهای ما سایه‌ای برروی زمین است."},{"v":10,"t":"آیا ایشان تو را تعلیم ندهند وبا تو سخن نرانند؟ و از دل خود کلمات بیرون نیارند؟"},{"v":11,"t":"آیا نی، بی‌خلاب می‌روید، یا قصب، بی‌آب نمو می‌کند؟"},{"v":12,"t":"هنگامی که هنوز سبزاست و بریده نشده، پیش از هر گیاه خشک می‌شود."},{"v":13,"t":"همچنین است راه جمیع فراموش کنندگان خدا. و امید ریاکار ضایع می شود،"},{"v":14,"t":"که امید او منقطع می‌شود، واعتمادش خانه عنکبوت است."},{"v":15,"t":"بر خانه خودتکیه می‌کند و نمی ایستد، به آن متمسک می‌شودو لیکن قایم نمی ماند."},{"v":16,"t":"پیش روی آفتاب، تر وتازه می‌شود و شاخه هایش در باغش پهن می‌گردد."},{"v":17,"t":"ریشه هایش بر توده های سنگ درهم بافته می‌شود، و بر سنگلاخ نگاه می‌کند."},{"v":18,"t":"اگر ازجای خود کنده شود، او را انکار کرده، می‌گوید: تو را نمی بینم."},{"v":19,"t":"اینک خوشی طریقش همین است و دیگران از خاک خواهند رویید."},{"v":20,"t":"هماناخدا مرد کامل را حقیر نمی شمارد، و شریر رادستگیری نمی نماید،"},{"v":21,"t":"تا دهان تو را از خنده پرکند، و لبهایت را از آواز شادمانی."},{"v":22,"t":"خصمان توبه خجالت ملبس خواهند شد، و خیمه شریران نابود خواهد گردید.»"}]},"9":{"fa":[{"v":1,"t":"پس ایوب در جواب گفت:"},{"v":2,"t":"«یقین می‌دانم که چنین است. لیکن انسان نزد خدا چگونه عادل شمرده شود؟"},{"v":3,"t":"اگر بخواهد با وی منازعه نماید، یکی از هزار او را جواب نخواهد داد."},{"v":4,"t":"اودر ذهن حکیم و در قوت تواناست. کیست که با اومقاومت کرده و کامیاب شده باشد؟"},{"v":5,"t":"آنکه کوههارا منتقل می‌سازد و نمی فهمند، و در غضب خویش آنها را واژگون می‌گرداند،"},{"v":6,"t":"که زمین را ازمکانش می‌جنباند، و ستونهایش متزلزل می‌شود."},{"v":7,"t":"که آفتاب را امر می‌فرماید و طلوع نمی کند وستارگان را مختوم می‌سازد."},{"v":8,"t":"که به تنهایی، آسمانها را پهن می‌کند و بر موجهای دریامی خرامد."},{"v":9,"t":"که دب اکبر و جبار و ثریا را آفرید، و برجهای جنوب را"},{"v":10,"t":"که کارهای عظیم بی‌قیاس را می‌کند و کارهای عجیب بی‌شمار را."},{"v":11,"t":"اینک از من می‌گذرد و او را نمی بینم، و عبور می‌کند واو را احساس نمی نمایم."},{"v":12,"t":"اینک او می‌رباید وکیست که او را منع نماید؟ و کیست که به او تواندگفت: چه می‌کنی؟"},{"v":13,"t":"خدا خشم خود را بازنمی دارد و مددکاران رحب زیر او خم می‌شوند."},{"v":14,"t":"«پس به طریق اولی، من کیستم که او راجواب دهم و سخنان خود را بگزینم تا با اومباحثه نمایم؟"},{"v":15,"t":"که اگر عادل می‌بودم، او راجواب نمی دادم، بلکه نزد داور خود استغاثه می‌نمودم."},{"v":16,"t":"اگر او را می‌خواندم و مرا جواب می‌داد، باور نمی کردم که آواز مرا شنیده است."},{"v":17,"t":"زیرا که مرا به تندبادی خرد می‌کند و بی‌سبب، زخمهای مرا بسیار می‌سازد."},{"v":18,"t":"مرا نمی گذارد که نفس بکشم، بلکه مرا به تلخیها پر می‌کند."},{"v":19,"t":"اگردرباره قوت سخن گوییم، اینک او قادر است؛ واگر درباره انصاف، کیست که وقت را برای من تعیین کند؟"},{"v":20,"t":"اگر عادل می‌بودم دهانم مرا مجرم می‌ساخت، و اگر کامل می‌بودم مرا فاسق می‌شمرد."},{"v":21,"t":"اگر کامل هستم، خویشتن رانمی شناسم، و جان خود را مکروه می‌دارم."},{"v":22,"t":"این امر برای همه یکی است. بنابراین می‌گویم که اوصالح است و شریر را هلاک می‌سازد."},{"v":23,"t":"اگرتازیانه ناگهان بکشد، به امتحان بی‌گناهان استهزامی کند."},{"v":24,"t":"جهان به‌دست شریران داده شده است و روی حاکمانش را می‌پوشاند. پس اگر چنین نیست، کیست که می‌کند؟"},{"v":25,"t":"و روزهایم از پیک تیزرفتار تندروتر است، می‌گریزد و نیکویی رانمی بیند."},{"v":26,"t":"مثل کشتیهای تیزرفتار می‌گریزد و مثل عقاب که بر شکار فرود آید."},{"v":27,"t":"اگر فکر کنم که ناله خود را فراموش کنم و ترش رویی خود رادور کرده، گشاده رو شوم،"},{"v":28,"t":"از تمامی مشقتهای خود می‌ترسم و می‌دانم که مرا بی‌گناه نخواهی شمرد،"},{"v":29,"t":"چونکه ملزم خواهم شد. پس چرا بیجازحمت بکشم؟"},{"v":30,"t":"اگر خویشتن را به آب برف غسل دهم، و دستهای خود را به اشنان پاک کنم،"},{"v":31,"t":"آنگاه مرا در لجن فرو می‌بری، و رختهایم مرامکروه می‌دارد."},{"v":32,"t":"زیرا که او مثل من انسان نیست که او را جواب بدهم و با هم به محاکمه بیاییم."},{"v":33,"t":"در میان ما حکمی نیست که بر هر دوی مادست بگذارد."},{"v":34,"t":"کاش که عصای خود را از من بردارد، و هیبت او مرا نترساند."},{"v":35,"t":"آنگاه سخن می‌گفتم و از او نمی ترسیدم، لیکن من در خودچنین نیستم."}]},"10":{"fa":[{"v":1,"t":"«جانم از حیاتم بیزار است. پس ناله خود را روان می‌سازم و در تلخی جان خود سخن می‌رانم."},{"v":2,"t":"به خدا می‌گویم مرا ملزم مساز، و مرا بفهمان که از چه سبب با من منازعت می‌کنی؟"},{"v":3,"t":"آیا برای تو نیکو است که ظلم نمایی وعمل دست خود را حقیر شماری، و بر مشورت شریران بتابی؟"},{"v":4,"t":"آیا تو را چشمان بشر است؟ یامثل دیدن انسان می‌بینی؟"},{"v":5,"t":"آیا روزهای تو مثل روزهای انسان است؟ یا سالهای تو مثل روزهای مرد است؟"},{"v":6,"t":"که معصیت مرا تفحص می‌کنی وبرای گناهانم تجسس می‌نمایی؟"},{"v":7,"t":"اگر‌چه می‌دانی که شریر نیستم و از دست تو رهاننده‌ای نیست."},{"v":8,"t":"«دستهایت مرا جمیع و تمام سرشته است، و مرا آفریده است و آیا مرا هلاک می‌سازی؟"},{"v":9,"t":"به یادآور که مرا مثل سفال ساختی و آیا مرا به غباربرمی گردانی؟"},{"v":10,"t":"آیا مرا مثل شیر نریختی و مثل پنیر، منجمد نساختی؟"},{"v":11,"t":"مرا به پوست و گوشت ملبس نمودی و مرا با استخوانها و پیها بافتی."},{"v":12,"t":"حیات و احسان به من عطا فرمودی و لطف توروح مرا محافظت نمود."},{"v":13,"t":"اما این چیزها را دردل خود پنهان کردی، و می‌دانم که اینها در فکرتو بود."},{"v":14,"t":"اگر گناه کردم، مرا نشان کردی و مرا ازمعصیتم مبرا نخواهی ساخت."},{"v":15,"t":"اگر شریر هستم وای بر من! و اگر عادل هستم سر خود رابرنخواهم افراشت، زیرا از اهانت پر هستم ومصیبت خود را می‌بینم!"},{"v":16,"t":"و اگر (سرم )برافراشته شود، مثل شیر مرا شکار خواهی کرد و باز عظمت خود را بر من ظاهر خواهی ساخت."},{"v":17,"t":"گواهان خود را بر من پی درپی می‌آوری و غضب خویش را بر من می‌افزایی وافواج متعاقب یکدیگر به ضد منند."},{"v":18,"t":"پس برای چه مرا از رحم بیرون آوردی؟ کاش که جان می‌دادم و چشمی مرا نمی دید."},{"v":19,"t":"پس می‌بودم، چنانکه نبودم و از رحم مادرم به قبر برده می‌شدم."},{"v":20,"t":"آیا روزهایم قلیل نیست؟ پس مراترک کن، و از من دست بردار تا اندکی گشاده روشوم،"},{"v":21,"t":"قبل از آنکه بروم به‌جایی که از آن برنخواهم گشت، به زمین ظلمت و سایه موت!"},{"v":22,"t":"به زمین تاریکی غلیظ مثل ظلمات، زمین سایه موت و بی‌ترتیب که روشنایی آن مثل ظلمات است.»"}]},"11":{"fa":[{"v":1,"t":"و صوفر نعماتی در جواب گفت:"},{"v":2,"t":"«آیابه کثرت سخنان جواب نباید داد و مردپرگو عادل شمرده شود؟"},{"v":3,"t":"آیا بیهوده‌گویی تومردمان را ساکت کند و یا سخریه کنی و کسی تورا خجل نسازد؟"},{"v":4,"t":"و می‌گویی تعلیم من پاک است، و من در نظر تو بی‌گناه هستم."},{"v":5,"t":"و لیکن کاش که خدا سخن بگوید و لبهای خود را بر تو بگشاید،"},{"v":6,"t":"و اسرار حکمت را برای تو بیان کند. زیرا که درماهیت خود دو طرف دارد. پس بدان که خدا کمتراز گناهانت تو را سزا داده است."},{"v":7,"t":"آیا عمق های خدا را می‌توانی دریافت نمود؟ یا به کنه قادرمطلق توانی رسید؟"},{"v":8,"t":"مثل بلندیهای آسمان است؛ چه خواهی کرد؟ گودتر از هاویه است؛ چه توانی دانست؟"},{"v":9,"t":"پیمایش آن از جهان طویل تر واز دریا پهن تر است."},{"v":10,"t":"اگر سخت بگیرد و حبس نماید و به محاکمه دعوت کند کیست که او راممانعت نماید؟"},{"v":11,"t":"زیرا که بطالت مردم را می‌داندو شرارت را می‌بیند اگرچه در آن تامل نکند."},{"v":12,"t":"ومرد جاهل آنوقت فهیم می‌شود که بچه خروحشی، انسان متولد شود."},{"v":13,"t":"اگر تو دل خود راراست سازی و دستهای خود را بسوی او درازکنی،"},{"v":14,"t":"اگر در دست تو شرارت باشد، آن را ازخود دور کن، و بی‌انصافی در خیمه های تو ساکن نشود."},{"v":15,"t":"پس یقین روی خود را بی‌عیب برخواهی افراشت، و مستحکم شده، نخواهی ترسید."},{"v":16,"t":"زیرا که مشقت خود را فراموش خواهی کرد، و آن را مثل آب رفته به یاد خواهی آورد،"},{"v":17,"t":"و روزگار تو از وقت ظهر روشن ترخواهد شد، و اگرچه تاریکی باشد، مثل صبح خواهد گشت."},{"v":18,"t":"و مطمئن خواهی بود چونکه امید داری، و اطراف خود را تجسس نموده، ایمن خواهی خوابید."},{"v":19,"t":"و خواهی خوابید وترساننده‌ای نخواهد بود، و بسیاری تو راتملق خواهند نمود."},{"v":20,"t":"لیکن چشمان شریران کاهیده می‌شود و ملجای ایشان از ایشان نابود می‌گردد و امید ایشان جان کندن ایشان است.»"}]},"12":{"fa":[{"v":1,"t":"پس ایوب در جواب گفت:"},{"v":2,"t":"«به درستی که شما قوم هستید، و حکمت با شما خواهد مرد."},{"v":3,"t":"لیکن مرا نیز مثل شما فهم هست، و از شما کمتر نیستم. و کیست که مثل این چیزها را نمی داند؟"},{"v":4,"t":"برای رفیق خود مسخره گردیده‌ام. کسی‌که خدا را خوانده است و او رامستجاب فرموده، مرد عادل و کامل، مسخره شده است."},{"v":5,"t":"در افکار آسودگان، برای مصیبت اهانت است. مهیا شده برای هرکه پایش بلغزد."},{"v":6,"t":"خیمه های دزدان به سلامت است و آنانی که خدا را غضبناک می‌سازند ایمن هستند، که خدای خود را در دست خود می‌آورند."},{"v":7,"t":"«لیکن الان از بهایم بپرس و تو را تعلیم خواهند داد. و از مرغان هوا و برایت بیان خواهندنمود."},{"v":8,"t":"یا به زمین سخن بران و تو را تعلیم خواهدداد، و ماهیان دریا به تو خبر خواهند رسانید."},{"v":9,"t":"کیست که از جمیع این چیزها نمی فهمد که دست خداوند آنها را به‌جا آورده است،"},{"v":10,"t":"که جان جمیع زندگان در دست وی است، و روح جمیع افراد بشر؟"},{"v":11,"t":"آیا گوش سخنان رانمی آزماید، چنانکه کام خوراک خود رامی چشد؟"},{"v":12,"t":"نزد پیران حکمت است، و عمردراز فطانت می‌باشد."},{"v":13,"t":"لیکن حکمت و کبریایی نزد وی است. مشورت و فطانت از آن او است."},{"v":14,"t":"اینک او منهدم می‌سازد و نمی توان بنا نمود. انسان را می‌بندد و نمی توان گشود."},{"v":15,"t":"اینک آبهارا باز می‌دارد و خشک می‌شود، و آنها را رهامی کند و زمین را واژگون می‌سازد."},{"v":16,"t":"قوت ووجود نزد وی است. فریبنده و فریب خورده از آن او است."},{"v":17,"t":"مشیران را غارت زده می‌رباید، وحاکمان را احمق می‌گرداند."},{"v":18,"t":"بند پادشاهان را می گشاید و در کمر ایشان کمربند می‌بندد."},{"v":19,"t":"کاهنان را غارت زده می‌رباید، و زورآوران راسرنگون می‌سازد."},{"v":20,"t":"بلاغت معتمدین را نابودمی گرداند، و فهم پیران را برمی دارد."},{"v":21,"t":"اهانت رابر نجیبان می‌ریزد و کمربند مقتدران را سست می‌گرداند."},{"v":22,"t":"چیزهای عمیق را از تاریکی منکشف می‌سازد، و سایه موت را به روشنایی بیرون می‌آورد."},{"v":23,"t":"امت‌ها را ترقی می‌دهد و آنهارا هلاک می‌سازد، امت‌ها را وسعت می‌دهد وآنها را جلای وطن می‌فرماید."},{"v":24,"t":"عقل روسای قوم های زمین را می‌رباید، و ایشان را در بیابان آواره می‌گرداند، جایی که راه نیست."},{"v":25,"t":"درتاریکی کورانه راه می‌روند و نور نیست. و ایشان را مثل مستان افتان و خیزان می‌گرداند."}]},"13":{"fa":[{"v":1,"t":"«اینک چشم من همه این چیزها رادیده، و گوش من آنها را شنیده وفهمیده است."},{"v":2,"t":"چنانکه شما می‌دانید من هم می‌دانم. و من کمتر از شما نیستم."},{"v":3,"t":"لیکن می‌خواهم با قادر مطلق سخن گویم. و آرزو دارم که با خدا محاجه نمایم."},{"v":4,"t":"اما شما دروغها جعل می‌کنید، و جمیع شما طبیبان باطل هستید."},{"v":5,"t":"کاش که شما به کلی ساکت می‌شدید که این برای شما حکمت می‌بود."},{"v":6,"t":"پس حجت مرابشنوید. و دعوی لبهایم را گوش گیرید."},{"v":7,"t":"آیابرای خدا به بی‌انصافی سخن خواهید راند؟ و به جهت او با فریب تکلم خواهید نمود؟"},{"v":8,"t":"آیا برای او طرف داری خواهید نمود؟ و به جهت خدادعوی خواهید کرد؟"},{"v":9,"t":"آیا نیکو است که او شما راتفتیش نماید؟ یا چنانکه انسان را مسخره می‌نمایند او را مسخره می‌سازید."},{"v":10,"t":"البته شما را توبیخ خواهد کرد. اگر در خفا طرف داری نمایید."},{"v":11,"t":"آیا جلال او شما را هراسان نخواهد ساخت؟ و هیبت او بر شما مستولی نخواهد شد؟"},{"v":12,"t":"ذکرهای شما، مثل های غبار است. وحصارهای شما، حصارهای گل است."},{"v":13,"t":"«از من ساکت شوید و من سخن خواهم گفت. و هرچه خواهد، بر من واقع شود."},{"v":14,"t":"چراگوشت خود را با دندانم بگیرم و جان خود را دردستم بنهم؟"},{"v":15,"t":"اگرچه مرا بکشد، برای او انتظارخواهم کشید. لیکن راه خود را به حضور او ثابت خواهم ساخت."},{"v":16,"t":"این نیز برای من نجات خواهدشد. زیرا ریاکار به حضور او حاضر نمی شود."},{"v":17,"t":"بشنوید! سخنان مرا بشنوید. و دعوی من به گوشهای شما برسد."},{"v":18,"t":"اینک الان دعوی خود رامرتب ساختم. و می‌دانم که عادل شمرده خواهم شد."},{"v":19,"t":"کیست که بامن مخاصمه کند؟ پس خاموش شده جان را تسلیم خواهم کرد."},{"v":20,"t":"فقطدو چیز به من مکن. آنگاه خود را از حضور توپنهان نخواهم ساخت."},{"v":21,"t":"دست خود را از من دورکن. و هیبت تو مرا هراسان نسازد."},{"v":22,"t":"آنگاه بخوان و من جواب خواهم داد، یا اینکه من بگویم و مراجواب بده."},{"v":23,"t":"خطایا و گناهانم چقدر است؟ تقصیر و گناه مرا به من بشناسان."},{"v":24,"t":"چرا روی خود را از من می‌پوشانی؟ و مرا دشمن خودمی شماری؟"},{"v":25,"t":"آیا برگی را که از باد رانده شده است می‌گریزانی؟ و کاه خشک را تعاقب می‌کنی؟"},{"v":26,"t":"زیرا که چیزهای تلخ را به ضد من می‌نویسی، و گناهان جوانی‌ام را نصیب من می‌سازی."},{"v":27,"t":"و پایهای مرا در کنده می‌گذاری، وجمیع راههایم را نشان می‌کنی و گرد کف پاهایم خط می‌کشی؛"},{"v":28,"t":"و حال آنکه مثل چیز گندیده فاسد، و مثل جامه بید خورده هستم."}]},"14":{"fa":[{"v":1,"t":"قلیل الایام و پر از زحمات است."},{"v":2,"t":"مثل گل می‌روید و بریده می‌شود. و مثل سایه می‌گریزد و نمی ماند."},{"v":3,"t":"و آیا بر چنین شخص چشمان خود را می‌گشایی و مرا با خود به محاکمه می‌آوری؟"},{"v":4,"t":"کیست که چیز طاهر را ازچیز نجس بیرون آورد؟ هیچکس نیست."},{"v":5,"t":"چونکه روزهایش مقدر است و شماره ماههایش نزد توست و حدی از برایش گذاشته‌ای که از آن تجاوز نتواند نمود."},{"v":6,"t":"از او رو بگردان تاآرام گیرد. و مثل مزدور روزهای خود را به انجام رساند."},{"v":7,"t":"«زیرا برای درخت امیدی است که اگر بریده شود باز خواهد رویید، و رمونهایش نابودنخواهد شد."},{"v":8,"t":"اگر‌چه ریشه‌اش در زمین کهنه شود، و تنه آن در خاک بمیرد."},{"v":9,"t":"لیکن از بوی آب، رمونه می‌کند و مثل نهال نو، شاخه‌ها می‌آورد."},{"v":10,"t":"اما مرد می‌میرد و فاسد می‌شود و آدمی چون جان را سپارد کجا است؟"},{"v":11,"t":"چنانکه آبها از دریازایل می‌شود، و نهرها ضایع و خشک می‌گردد."},{"v":12,"t":"همچنین انسان می‌خوابد و برنمی خیزد، تانیست شدن آسمانها بیدار نخواهند شد و ازخواب خود برانگیخته نخواهند گردید."},{"v":13,"t":"کاش که مرا در هاویه پنهان کنی؛ و تا غضبت فرو نشیند، مرا مستور سازی؛ و برایم زمانی تعیین نمایی تا مرا به یاد آوری."},{"v":14,"t":"اگر مرد بمیرد باردیگر زنده شود؛ در تمامی روزهای مجاهده خودانتظار خواهم کشید، تا وقت تبدیل من برسد."},{"v":15,"t":"تو ندا خواهی کرد و من جواب خواهم داد، و به صنعت دست خود مشتاق خواهی شد."},{"v":16,"t":"اما الان قدمهای مرا می‌شماری و آیا برگناه من پاسبانی نمی کنی؟"},{"v":17,"t":"معصیت من در کیسه مختوم است. و خطای مرا مسدود ساخته‌ای."},{"v":18,"t":"به درستی کوهی که می‌افتد فانی می‌شود وصخره از مکانش منتقل می‌گردد."},{"v":19,"t":"آب سنگهارا می‌ساید، و سیلهایش خاک زمین را می‌برد. همچنین امید انسان را تلف می‌کنی،"},{"v":20,"t":"بر او تا به ابد غلبه می‌کنی، پس می‌رود. روی او را تغییرمی دهی و او را رها می‌کنی."},{"v":21,"t":"پسرانش به عزت می‌رسند و او نمی داند. یا به ذلت می‌افتند و ایشان را به نظر نمی آورد."},{"v":22,"t":"برای خودش فقط جسد اواز درد بی‌تاب می‌شود. و برای خودش جان اوماتم می‌گیرد.»"}]},"15":{"fa":[{"v":1,"t":"پس الیفاز تیمانی در جواب گفت:"},{"v":2,"t":"«آیامرد حکیم از علم باطل جواب دهد؟ وبطن خود را از باد شرقی پر سازد؟"},{"v":3,"t":"آیا به سخن بی‌فایده محاجه نماید؟ و به کلماتی که هیچ نفع نمی بخشد؟"},{"v":4,"t":"اما تو خداترسی را ترک می‌کنی وتقوا را به حضور خدا ناقص می‌سازی."},{"v":5,"t":"زیرا که دهانت، معصیت تو را ظاهر می‌سازد و زبان حیله گران را اختیار می‌کنی."},{"v":6,"t":"دهان خودت تو راملزم می‌سازد و نه من، و لبهایت بر تو شهادت می‌دهد."},{"v":7,"t":"آیا شخص اول از آدمیان زاییده شده‌ای؟ و پیش از تلها به وجود آمده‌ای؟"},{"v":8,"t":"آیامشورت مخفی خدا را شنیده‌ای و حکمت را برخود منحصر ساخته‌ای؟"},{"v":9,"t":"چه می‌دانی که ما هم نمی دانیم؟ و چه می‌فهمی که نزد ما هم نیست؟"},{"v":10,"t":"نزد ما ریش سفیدان و پیران هستند که درروزها از پدر تو بزرگترند."},{"v":11,"t":"آیا تسلی های خدابرای تو کم است و کلام ملایم با تو؟"},{"v":12,"t":"چرا دلت تو را می‌رباید؟ و چرا چشمانت را بر هم می‌زنی"},{"v":13,"t":"که روح خود را به ضد خدا بر می‌گردانی، وچنین سخنان را از دهانت بیرون می‌آوری؟"},{"v":14,"t":"«انسان چیست که پاک باشد، و مولود زن که عادل شمرده شود؟"},{"v":15,"t":"اینک بر مقدسان خوداعتماد ندارد، و آسمانها در نظرش پاک نیست."},{"v":16,"t":"پس از طریق اولی انسان مکروه و فاسد که شرارت را مثل آب می‌نوشد."},{"v":17,"t":"من برای تو بیان می‌کنم پس مرا بشنو. و آنچه دیده‌ام حکایت می‌نمایم."},{"v":18,"t":"که حکیمان آن را از پدران خودروایت کردند و مخفی نداشتند،"},{"v":19,"t":"که به ایشان به تنهایی زمین داده شد، و هیچ غریبی از میان ایشان عبور نکرد،"},{"v":20,"t":"شریر در تمامی روزهایش مبتلای درد است. و سالهای شمرده شده برای مرد ظالم مهیا است."},{"v":21,"t":"صدای ترسها در گوش وی است. در وقت سلامتی تاراج کننده بر وی می‌آید."},{"v":22,"t":"باور نمی کند که از تاریکی خواهد برگشت وشمشیر برای او مراقب است."},{"v":23,"t":"برای نان می‌گردد و می‌گوید کجاست. و می‌داند که روزتاریکی نزد او حاضر است."},{"v":24,"t":"تنگی و ضیق او رامی ترساند، مثل پادشاه مهیای جنگ بر او غلبه می‌نماید."},{"v":25,"t":"زیرا دست خود را به ضد خدا درازمی کند و بر قادر مطلق تکبر می‌نماید."},{"v":26,"t":"با گردن بلند بر او تاخت می‌آورد، با گل میخهای سخت سپر خویش،"},{"v":27,"t":"چونکه روی خود را به پیه پوشانیده، و کمر خود را با شحم ملبس ساخته است."},{"v":28,"t":"و در شهرهای ویران و خانه های غیرمسکون که نزدیک به خراب شدن است ساکن می‌شود."},{"v":29,"t":"او غنی نخواهد شد و دولتش پایدارنخواهد ماند، و املاک او در زمین زیاد نخواهد گردید."},{"v":30,"t":"از تاریکی رها نخواهد شد، و آتش، شاخه هایش را خواهد خشکانید، و به نفخه دهان او زائل خواهد شد."},{"v":31,"t":"به بطالت توکل ننماید وخود را فریب ندهد، والا بطالت اجرت او خواهدبود."},{"v":32,"t":"قبل از رسیدن وقتش تمام ادا خواهد شدو شاخه او سبز نخواهد ماند."},{"v":33,"t":"مثل مو، غوره خود را خواهد افشاند، و مثل زیتون، شکوفه خود را خواهد ریخت،"},{"v":34,"t":"زیرا که جماعت ریاکاران، بی‌کس خواهند ماند، و خیمه های رشوه خواران را آتش خواهد سوزانید."},{"v":35,"t":"به شقاوت حامله شده، معصیت را می‌زایند و شکم ایشان فریب را آماده می‌کند.»"}]},"16":{"fa":[{"v":1,"t":"پس ایوب در جواب گفت:"},{"v":2,"t":"«بسیارچیزها مثل این شنیدم. تسلی دهندگان مزاحم همه شما هستید."},{"v":3,"t":"آیا سخنان باطل راانتها نخواهد شد؟ و کیست که تو را به جواب دادن تحریک می‌کند؟"},{"v":4,"t":"من نیز مثل شمامی توانستم بگویم، اگر جان شما در جای جان من می‌بود، و سخنها به ضد شما ترتیب دهم، و سرخود را بر شما بجنبانم،"},{"v":5,"t":"لیکن شما را به دهان خود تقویت می‌دادم و تسلی لبهایم غم شما رارفع می‌نمود."},{"v":6,"t":"«اگر من سخن گویم، غم من رفع نمی گردد؛ واگر ساکت شوم مرا چه راحت حاصل می‌شود؟"},{"v":7,"t":"لیکن الان او مرا خسته نموده است. تو تمامی جماعت مرا ویران ساخته‌ای."},{"v":8,"t":"مرا سخت گرفتی و این بر من شاهد شده است. و لاغری من به ضدمن برخاسته، روبرویم شهادت می‌دهد."},{"v":9,"t":"در غضب خود مرا دریده و بر من جفا نموده است. دندانهایش را بر من افشرده و مثل دشمنم چشمان خود را بر من تیز کرده است."},{"v":10,"t":"دهان خود را بر من گشوده‌اند، بر رخسار من به استحقارزده‌اند، به ضد من با هم اجتماع نموده‌اند."},{"v":11,"t":"خدامرا به‌دست ظالمان تسلیم نموده، و مرا به‌دست شریران افکنده است."},{"v":12,"t":"چون در راحت بودم مراپاره پاره کرده است، و گردن مرا گرفته، مرا خردکرده، و مرا برای هدف خود نصب نموده است."},{"v":13,"t":"تیرهایش مرا احاطه کرد. گرده هایم را پاره می‌کند و شفقت نمی نماید. و زهره مرا به زمین می‌ریزد."},{"v":14,"t":"مرا زخم بر زخم، مجروح می‌سازد ومثل جبار، بر من حمله می‌آورد."},{"v":15,"t":"بر پوست خود پلاس دوخته‌ام، و شاخ خود را در خاک خوار نموده‌ام."},{"v":16,"t":"روی من از گریستن سرخ شده است، و بر مژگانم سایه موت است."},{"v":17,"t":"اگر‌چه هیچ بی‌انصافی در دست من نیست، و دعای من پاک است."},{"v":18,"t":"‌ای زمین خون مرا مپوشان، واستغاثه مرا آرام نباشد."},{"v":19,"t":"اینک الان نیز شاهد من در آسمان است، و گواه من در اعلی علیین."},{"v":20,"t":"دوستانم مرا استهزا می‌کنند، لیکن چشمانم نزد خدا اشک می‌ریزد."},{"v":21,"t":"و آیا برای انسان نزدخدا محاجه می‌کند، مثل بنی آدم که برای همسایه خود می‌نماید؟"},{"v":22,"t":"زیرا سالهای اندک سپری می‌شود، پس به راهی که برنمی گردم، خواهم رفت."}]},"17":{"fa":[{"v":1,"t":"«روح من تلف شده، و روزهایم تمام گردیده، و قبر برای من حاضر است."},{"v":2,"t":"به درستی که استهزاکنندگان نزد منند، و چشم من در منازعت ایشان دائم می‌ماند."},{"v":3,"t":"الان گرو بده و به جهت من نزد خود ضامن باش. والا کیست که به من دست دهد؟"},{"v":4,"t":"چونکه دل ایشان را از حکمت منع کرده‌ای، بنابراین ایشان را بلند نخواهی ساخت."},{"v":5,"t":"کسی‌که دوستان خود را به تاراج تسلیم کند، چشمان فرزندانش تار خواهد شد."},{"v":6,"t":"مرا نزدامت‌ها مثل ساخته است، و مثل کسی‌که بر رویش آب دهان اندازند شده‌ام."},{"v":7,"t":"چشم من از غصه کاهیده شده است، و تمامی اعضایم مثل سایه گردیده."},{"v":8,"t":"راستان به‌سبب این، حیران می‌مانند وصالحان خویشتن را بر ریاکاران برمی انگیزانند."},{"v":9,"t":"لیکن مرد عادل به طریق خود متمسک می‌شود، و کسی‌که دست پاک دارد، در قوت ترقی خواهدنمود."},{"v":10,"t":"«اما همه شما برگشته، الان بیایید و در میان شما حکیمی نخواهم یافت."},{"v":11,"t":"روزهای من گذشته، و قصدهای من و فکرهای دلم منقطع شده است."},{"v":12,"t":"شب را به روز تبدیل می‌کنند و باوجود تاریکی می‌گویند روشنایی نزدیک است."},{"v":13,"t":"وقتی که امید دارم هاویه خانه من می‌باشد، وبستر خود را در تاریکی می‌گسترانم،"},{"v":14,"t":"و به هلاکت می‌گویم تو پدر من هستی و به کرم که تومادر و خواهر من می‌باشی."},{"v":15,"t":"پس امید من کجااست؟ و کیست که امید مرا خواهد دید؟"},{"v":16,"t":"تابندهای هاویه فرو می‌رود، هنگامی که با هم درخاک نزول (نماییم ).»"}]},"18":{"fa":[{"v":1,"t":"پس بلدد شوحی در جواب گفت:"},{"v":2,"t":"«تابه کی برای سخنان، دامها می‌گسترانید؟ تفکر کنید و بعد از آن تکلم خواهیم نمود."},{"v":3,"t":"چرا مثل بهایم شمرده شویم؟ و در نظر شما نجس نماییم؟"},{"v":4,"t":"‌ای که در غضب خود خویشتن را پاره می‌کنی، آیا به‌خاطر تو زمین متروک شود، یاصخره از جای خود منتقل گردد؟"},{"v":5,"t":"البته روشنایی شریران خاموش خواهد شد، و شعله آتش ایشان نور نخواهد داد."},{"v":6,"t":"در خیمه اوروشنایی به تاریکی مبدل می‌گردد، و چراغش براو خاموش خواهد شد."},{"v":7,"t":"قدمهای قوتش تنگ می‌شود. و مشورت خودش او را به زیر خواهدافکند."},{"v":8,"t":"زیرا به پایهای خود در دام خواهد افتاد، و به روی تله‌ها راه خواهد رفت."},{"v":9,"t":"تله پاشنه او راخواهد گرفت. و دام، او را به زور نگاه خواهدداشت."},{"v":10,"t":"دام برایش در زمین پنهان شده است، وتله برایش در راه."},{"v":11,"t":"ترسها از هر طرف او راهراسان می‌کند، و به او چسبیده، وی رامی گریزاند."},{"v":12,"t":"شقاوت، برای او گرسنه است، وذلت، برای لغزیدن او حاضر است."},{"v":13,"t":"اعضای جسد او را می‌خورد. نخست زاده موت، جسد اورا می‌خورد."},{"v":14,"t":"آنچه بر آن اعتماد می‌داشت، ازخیمه او ربوده می‌شود، و خود او نزد پادشاه ترسها رانده می‌گردد."},{"v":15,"t":"کسانی که از وی نباشنددر خیمه او ساکن می‌گردند، و گوگرد بر مسکن اوپاشیده می‌شود."},{"v":16,"t":"ریشه هایش از زیرمی خشکد، و شاخه‌اش از بالا بریده خواهد شد."},{"v":17,"t":"یادگار او از زمین نابود می‌گردد، و در کوچه هااسم نخواهد داشت."},{"v":18,"t":"از روشنایی به تاریکی رانده می‌شود. و او را از ربع مسکون خواهندگریزانید."},{"v":19,"t":"او را در میان قومش نه اولاد و نه ذریت خواهد بود، و در ماوای او کسی باقی نخواهد ماند."},{"v":20,"t":"متاخرین از روزگارش متحیر خواهند شد، چنانکه بر متقدمین، ترس مستولی شده بود."},{"v":21,"t":"به درستی که مسکن های شریران چنین می‌باشد، و مکان کسی‌که خدا رانمی شناسد مثل این است.»"}]},"19":{"fa":[{"v":1,"t":"پس ایوب در جواب گفت:"},{"v":2,"t":"«تا به کی جان مرا می‌رنجانید؟ و مرا به سخنان خود فرسوده می‌سازید؟"},{"v":3,"t":"این ده مرتبه است که مرا مذمت نمودید، و خجالت نمی کشید که با من سختی می‌کنید؟"},{"v":4,"t":"و اگر فی الحقیقه خطا کرده‌ام، خطای من نزد من می‌ماند."},{"v":5,"t":"اگر فی الواقع بر من تکبر نمایید و عار مرا بر من اثبات کنید،"},{"v":6,"t":"پس بدانید که خدا دعوی مرا منحرف ساخته، و به دام خود مرا احاطه نموده است."},{"v":7,"t":"اینک از ظلم، تضرع می‌نمایم و مستجاب نمی شوم و استغاثه می‌کنم و دادرسی نیست."},{"v":8,"t":"طریق مرا حصارنموده است که از آن نمی توانم گذشت و برراههای من تاریکی را گذارده است."},{"v":9,"t":"جلال مرا ازمن کنده است و تاج را از سر من برداشته،"},{"v":10,"t":"مرا ازهر طرف خراب نموده، پس هلاک شدم. و مثل درخت، ریشه امید مرا کنده است."},{"v":11,"t":"غضب خودرا بر من افروخته، و مرا یکی از دشمنان خودشمرده است."},{"v":12,"t":"فوجهای او با هم می‌آیند و راه خود را بر من بلند می‌کنند و به اطراف خیمه من اردو می‌زنند."},{"v":13,"t":"«برادرانم را از نزد من دور کرده است وآشنایانم از من بالکل بیگانه شده‌اند."},{"v":14,"t":"خویشانم مرا ترک نموده و آشنایانم مرا فراموش کرده‌اند."},{"v":15,"t":"نزیلان خانه‌ام و کنیزانم مرا غریب می‌شمارند، و در نظر ایشان بیگانه شده‌ام."},{"v":16,"t":"غلام خود راصدا می‌کنم و مرا جواب نمی دهد، اگر‌چه او را به دهان خود التماس بکنم."},{"v":17,"t":"نفس من نزد زنم مکروه شده است و تضرع من نزد اولاد رحم مادرم."},{"v":18,"t":"بچه های کوچک نیز مرا حقیرمی شمارند و چون برمی خیزم به ضد من حرف می‌زنند."},{"v":19,"t":"همه اهل مشورتم از من نفرت می‌نمایند، و کسانی را که دوست می‌داشتم از من برگشته‌اند."},{"v":20,"t":"استخوانم به پوست و گوشتم چسبیده است، و با پوست دندانهای خودخلاصی یافته‌ام."},{"v":21,"t":"بر من ترحم کنید! ترحم کنیدشما‌ای دوستانم! زیرا دست خدا مرا لمس نموده است."},{"v":22,"t":"چرا مثل خدا بر من جفا می‌کنید وازگوشت من سیر نمی شوید."},{"v":23,"t":"کاش که سخنانم الان نوشته می‌شد! کاش که در کتابی ثبت می‌گردید،"},{"v":24,"t":"و با قلم آهنین و سرب بر صخره‌ای تا به ابد کنده می‌شد!"},{"v":25,"t":"و من می‌دانم که ولی من زنده است، و در ایام آخر، بر زمین خواهدبرخاست."},{"v":26,"t":"و بعد از آنکه این پوست من تلف شود، بدون جسدم نیز خدا را خواهم دید."},{"v":27,"t":"ومن او را برای خود خواهم دید. و چشمان من بر اوخواهد نگریست و نه چشم دیگری. اگر‌چه گرده هایم در اندرونم تلف شده باشد."},{"v":28,"t":"اگربگویید چگونه بر او جفا نماییم و حال آنگاه اصل امر در من یافت می‌شود."},{"v":29,"t":"پس از شمشیربترسید، زیرا که سزاهای شمشیر غضبناک است، تا دانسته باشید که داوری خواهد بود.»"}]},"20":{"fa":[{"v":1,"t":"پس صوفر نعماتی در جواب گفت:"},{"v":2,"t":"«از این جهت فکرهایم مرا به جواب دادن تحریک می‌کند و به این سبب، من تعجیل می نمایم."},{"v":3,"t":"سرزنش توبیخ خود را شنیدم، و ازفطانتم روح من مرا جواب می‌دهد."},{"v":4,"t":"آیا این را ازقدیم ندانسته‌ای، از زمانی که انسان بر زمین قرارداده شد،"},{"v":5,"t":"که شادی شریران، اندک زمانی است، و خوشی ریاکاران، لحظه‌ای؟"},{"v":6,"t":"اگر‌چه شوکت اوتا به آسمان بلند شود، و سر خود را تا به فلک برافرازد."},{"v":7,"t":"لیکن مثل فضله خود تا به ابد هلاک خواهد شد، و بینندگانش خواهند گفت: کجااست؟"},{"v":8,"t":"مثل خواب، می‌پرد و یافت نمی شود. ومثل رویای شب، او را خواهند گریزانید."},{"v":9,"t":"چشمی که او را دیده است دیگر نخواهد دید، ومکانش باز بر او نخواهد نگریست."},{"v":10,"t":"فرزندانش نزد فقیران تذلل خواهند کرد، و دستهایش دولت او را پس خواهد داد."},{"v":11,"t":"استخوانهایش از جوانی پر است، لیکن همراه او در خاک خواهد خوابید."},{"v":12,"t":"اگر‌چه شرارت در دهانش شیرین باشد، و آن را زیر زبانش پنهان کند."},{"v":13,"t":"اگر‌چه او را دریغ داردو از دست ندهد، و آن را در میان کام خود نگاه دارد."},{"v":14,"t":"لیکن خوراک او در احشایش تبدیل می‌شود، و در اندرونش زهرمار می‌گردد."},{"v":15,"t":"دولت را فرو برده است و آن را قی خواهد کرد، و خدا آن را از شکمش بیرون خواهد نمود."},{"v":16,"t":"اوزهر مارها را خواهد مکید، و زبان افعی او راخواهد کشت."},{"v":17,"t":"بر رودخانه‌ها نظر نخواهندکرد، بر نهرها و جویهای شهد و شیر."},{"v":18,"t":"ثمره زحمت خود را رد کرده، آن را فرو نخواهد برد، وبرحسب دولتی که کسب کرده است، شادی نخواهد نمود."},{"v":19,"t":"زیرا فقیران را زبون ساخته وترک کرده است. پس خانه‌ای را که دزدیده است، بنا نخواهد کرد."},{"v":20,"t":"«زیرا که در حرص خود قناعت را ندانست. پس از نفایس خود، چیزی استرداد نخواهد کرد."},{"v":21,"t":"چیزی نمانده است که نخورده باشد. پس برخورداری او دوام نخواهد داشت."},{"v":22,"t":"هنگامی که دولت او بی‌نهایت گردد، در تنگی گرفتار می‌شود، و دست همه ذلیلان بر او استیلاخواهد یافت."},{"v":23,"t":"در وقتی که شکم خود را پرمی کند، خدا حدت خشم خود را بر او خواهدفرستاد، و حینی که می‌خورد آن را بر او خواهدبارانید."},{"v":24,"t":"از اسلحه آهنین خواهد گریخت وکمان برنجین، او را خواهد سفت."},{"v":25,"t":"آن رامی کشد و از جسدش بیرون می‌آید، و پیکان براق از زهره‌اش درمی رود و ترسها بر او استیلامی یابد."},{"v":26,"t":"تمامی تاریکی برای ذخایر او نگاه داشته شده است. و آتش ندمیده آنها را خواهدسوزانید، و آنچه را که در چادرش باقی است، خواهد خورد."},{"v":27,"t":"آسمانها عصیانش را مکشوف خواهد ساخت، و زمین به ضد او خواهدبرخاست."},{"v":28,"t":"محصول خانه‌اش زایل خواهد شد، و در روز غضب او نابود خواهد گشت."},{"v":29,"t":"این است نصیب مرد شریر از خدا و میراث مقدر او ازقادر مطلق.»"}]},"21":{"fa":[{"v":1,"t":"پس ایوب در جواب گفت:"},{"v":2,"t":"«بشنوید، کلام مرا بشنوید. و این، تسلی شماباشد."},{"v":3,"t":"با من تحمل نمایید تا بگویم، و بعد ازگفتنم استهزا نمایید."},{"v":4,"t":"و اما من، آیا شکایتم نزدانسان است؟ پس چرا بی‌صبر نباشم؟"},{"v":5,"t":"به من توجه کنید و تعجب نمایید، و دست به دهان بگذارید."},{"v":6,"t":"هرگاه به یاد می‌آورم، حیران می‌شوم. و لرزه جسد مرا می‌گیرد."},{"v":7,"t":"چرا شریران زنده می‌مانند، پیر می‌شوند و در توانایی قوی می‌گردند؟"},{"v":8,"t":"ذریت ایشان به حضور ایشان، با ایشان استوار می‌شوند و اولاد ایشان در نظرایشان."},{"v":9,"t":"خانه های ایشان، از ترس ایمن می‌باشد وعصای خدا بر ایشان نمی آید."},{"v":10,"t":"گاو نر ایشان جماع می‌کند و خطا نمی کند و گاو ایشان می‌زایدو سقط نمی نماید."},{"v":11,"t":"بچه های خود را مثل گله بیرون می‌فرستند و اطفال ایشان رقص می‌کنند."},{"v":12,"t":"با دف وعود می‌سرایند، و با صدای نای شادی می‌نمایند."},{"v":13,"t":"روزهای خود را در سعادتمندی صرف می‌کنند، و به لحظه‌ای به هاویه فرودمی روند."},{"v":14,"t":"و به خدا می‌گویند: از ما دور شو زیراکه معرفت طریق تو را نمی خواهیم."},{"v":15,"t":"قادرمطلق کیست که او را عبادت نماییم، و ما را چه فایده که از او استدعا نماییم."},{"v":16,"t":"اینک سعادتمندی ایشان در دست ایشان نیست. کاش که مشورت شریران از من دور باشد."},{"v":17,"t":"«بسا چراغ شریران خاموش می‌شود وذلت ایشان به ایشان می‌رسد، و خدا در غضب خود دردها را نصیب ایشان می‌کند."},{"v":18,"t":"مثل سفال پیش روی باد می‌شوند و مثل کاه که گردبادپراکنده می‌کند."},{"v":19,"t":"خدا گناهش را برای فرزندانش ذخیره می‌کند، و او را مکافات می‌رساند و خواهد دانست."},{"v":20,"t":"چشمانش هلاکت او را خواهد دید، و از خشم قادر مطلق خواهدنوشید."},{"v":21,"t":"زیرا که بعد از او در خانه‌اش او را چه شادی خواهد بود، چون عدد ماههایش منقطع شود؟"},{"v":22,"t":"آیا خدا را علم توان آموخت؟ چونکه اوبر اعلی علیین داوری می‌کند."},{"v":23,"t":"یکی در عین قوت خود می‌میرد، در حالی که بالکل در امنیت وسلامتی است."},{"v":24,"t":"قدحهای او پر از شیر است، ومغز استخوانش تر و تازه است."},{"v":25,"t":"و دیگری درتلخی جان می‌میرد و از نیکویی هیچ لذت نمی برد."},{"v":26,"t":"اینها باهم در خاک می‌خوابند و کرمها ایشان را می‌پوشانند."},{"v":27,"t":"اینک افکار شما رامی دانم و تدبیراتی که ناحق بر من می‌اندیشید."},{"v":28,"t":"زیرا می‌گویید کجاست خانه امیر، و خیمه های مسکن شریران؟"},{"v":29,"t":"آیا از راه گذریان نپرسیدید؟ ودلایل ایشان را انکار نمی توانید نمود،"},{"v":30,"t":"که شریران برای روز ذلت نگاه داشته می‌شوند و درروز غضب، بیرون برده می‌گردند."},{"v":31,"t":"کیست که راهش را پیش رویش بیان کند، و جزای آنچه راکه کرده است به او برساند؟"},{"v":32,"t":"که آخر او را به قبرخواهند برد، و بر مزار او نگاهبانی خواهند کرد."},{"v":33,"t":"کلوخهای وادی برایش شیرین می‌شود وجمیع آدمیان در عقب او خواهند رفت، چنانکه قبل از او بیشماره رفته‌اند."},{"v":34,"t":"پس چگونه مراتسلی باطل می‌دهید که در جوابهای شما محض خیانت می‌ماند!»"}]},"22":{"fa":[{"v":1,"t":"پس الیفاز تیمانی در جواب گفت:"},{"v":2,"t":"«آیا مرد به خدا فایده برساند؟ البته مرد دانا برای خویشتن مفید است."},{"v":3,"t":"آیا اگر توعادل باشی، برای قادر مطلق خوشی رخ می‌نماید؟ یا اگر طریق خود را راست سازی، او رافایده می‌شود؟"},{"v":4,"t":"آیا به‌سبب ترس تو، تو را توبیخ می‌نماید؟ یا با تو به محاکمه داخل خواهد شد؟"},{"v":5,"t":"آیا شرارت تو عظیم نیست و عصیان تو بی‌انتهانی،"},{"v":6,"t":"چونکه از برادران خود بی‌سبب گرو گرفتی و لباس برهنگان را کندی،"},{"v":7,"t":"به تشنگان آب ننوشانیدی، و از گرسنگان نان دریغ داشتی؟"},{"v":8,"t":"امامرد جبار، زمین از آن او می‌باشد و مرد عالیجاه، در آن ساکن می‌شود."},{"v":9,"t":"بیوه‌زنان را تهی‌دست رد نمودی، و بازوهای یتیمان شکسته گردید."},{"v":10,"t":"بنابراین دامها تو را احاطه می‌نماید و ترس، ناگهان تو را مضطرب می‌سازد."},{"v":11,"t":"یا تاریکی که آن را نمی بینی و سیلابها تو را می‌پوشاند."},{"v":12,"t":"آیاخدا مثل آسمانها بلند نیست؟ و سر ستارگان رابنگر چگونه عالی هستند."},{"v":13,"t":"و تو می‌گویی خداچه می‌داند و آیا از تاریکی غلیظ داوری تواندنمود؟"},{"v":14,"t":"ابرها ستر اوست پس نمی بیند، و بردایره افلاک می‌خرامد."},{"v":15,"t":"آیا طریق قدما را نشان کردی که مردمان شریر در آن سلوک نمودند،"},{"v":16,"t":"که قبل از زمان خود ربوده شدند، و اساس آنهامثل نهر ریخته شد"},{"v":17,"t":"که به خدا گفتند: از ما دورشو و قادر مطلق برای ما چه تواند کرد؟"},{"v":18,"t":"و حال آنگاه او خانه های ایشان را از چیزهای نیکو پرساخت. پس مشورت شریران از من دور شود."},{"v":19,"t":"«عادلان چون آن را بینند، شادی خواهندنمود و بی‌گناهان بر ایشان استهزا خواهند کرد."},{"v":20,"t":"آیا مقاومت کنندگان ما منقطع نشدند؟ و آتش بقیه ایشان را نسوزانید؟"},{"v":21,"t":"پس حال با او انس بگیر و سالم باش. و به این منوال نیکویی به توخواهد رسید."},{"v":22,"t":"تعلیم را از دهانش قبول نما، وکلمات او را در دل خود بنه."},{"v":23,"t":"اگر به قادرمطلق بازگشت نمایی، بنا خواهی شد. و اگر شرارت رااز خیمه خود دور نمایی"},{"v":24,"t":"و اگر گنج خود را درخاک و طلای اوفیر را در سنگهای نهرهابگذاری،"},{"v":25,"t":"آنگاه قادر مطلق گنج تو و نقره خالص برای تو خواهد بود،"},{"v":26,"t":"زیرا در آنوقت ازقادر مطلق تلذذ خواهی یافت، و روی خود را به طرف خدا برخواهی افراشت."},{"v":27,"t":"نزد او دعاخواهی کرد و او تو را اجابت خواهد نمود، و نذرهای خود را ادا خواهی ساخت."},{"v":28,"t":"امری راجزم خواهی نمود و برایت برقرار خواهد شد، وروشنایی بر راههایت خواهد تابید."},{"v":29,"t":"وقتی که ذلیل شوند، خواهی گفت: رفعت باشد، و فروتنان را نجات خواهد داد."},{"v":30,"t":"کسی را که بی‌گناه نباشدخواهد رهانید، و به پاکی دستهای تو رهانیده خواهد شد.»"}]},"23":{"fa":[{"v":1,"t":"پس ایوب در جواب گفت:"},{"v":2,"t":"«امروز نیز شکایت من تلخ است، وضرب من از ناله من سنگینتر."},{"v":3,"t":"کاش می‌دانستم که او را کجا یابم، تا آنکه نزد کرسی او بیایم."},{"v":4,"t":"آنگاه دعوی خود را به حضور وی ترتیب می‌دادم، ودهان خود را از حجت‌ها پر می‌ساختم."},{"v":5,"t":"سخنانی را که در جواب من می‌گفت می‌دانستم، و آنچه راکه به من می‌گفت می‌فهمیدم."},{"v":6,"t":"آیا به عظمت قوت خود با من مخاصمه می‌نمود؟ حاشا! بلکه به من التفات می‌کرد."},{"v":7,"t":"آنگاه مرد راست با اومحاجه می‌نمود و از داور خود تا به ابد نجات می‌یافتم."},{"v":8,"t":"اینک به طرف مشرق می‌روم و اویافت نمی شود و به طرف مغرب و او را نمی بینم."},{"v":9,"t":"به طرف شمال جایی که او عمل می‌کند، و او رامشاهده نمی کنم. و او خود را به طرف جنوب می‌پوشاند و او را نمی بینم،"},{"v":10,"t":"زیرا او طریقی راکه می‌روم می‌داند و چون مرا می‌آزماید، مثل طلابیرون می‌آیم."},{"v":11,"t":"پایم اثر اقدام او را گرفته است وطریق او را نگاه داشته، از آن تجاوز نمی کنم."},{"v":12,"t":"از فرمان لبهای وی برنگشتم و سخنان دهان اورا زیاده از رزق خود ذخیره کردم."},{"v":13,"t":"لیکن اوواحد است و کیست که او را برگرداند؟ و آنچه دل او می‌خواهد، به عمل می‌آورد."},{"v":14,"t":"زیرا آنچه را که بر من مقدر شده است بجا می‌آورد، و چیزهای بسیار مثل این نزد وی است."},{"v":15,"t":"از این جهت ازحضور او هراسان هستم، و چون تفکر می‌نمایم از او می‌ترسم،"},{"v":16,"t":"زیرا خدا دل مرا ضعیف کرده است، و قادرمطلق مرا هراسان گردانیده."},{"v":17,"t":"چونکه پیش از تاریکی منقطع نشدم، و ظلمت غلیظ را از نزد من نپوشانید."}]},"24":{"fa":[{"v":1,"t":"«چونکه زمانها از قادرمطلق مخفی نیست. پس چرا عارفان او ایام او راملاحظه نمی کنند؟"},{"v":2,"t":"بعضی هستند که حدود رامنتقل می‌سازند و گله‌ها را غصب نموده، می‌چرانند."},{"v":3,"t":"الاغهای یتیمان را می‌رانند و گاوبیوه‌زنان را به گرو می‌گیرند."},{"v":4,"t":"فقیران را از راه منحرف می‌سازند، و مسکینان زمین جمیع خویشتن را پنهان می‌کنند."},{"v":5,"t":"اینک مثل خروحشی به جهت کار خود به بیابان بیرون رفته، خوراک خود را می‌جویند و صحرا به ایشان نان برای فرزندان ایشان می‌رساند."},{"v":6,"t":"علوفه خود را درصحرا درو می‌کنند و تاکستان شریران راخوشه چینی می‌نمایند."},{"v":7,"t":"برهنه و بی‌لباس شب رابه‌سر می‌برند و در سرما پوششی ندارند."},{"v":8,"t":"ازباران کوهها تر می‌شوند و از عدم پناهگاه، صخره‌ها را در بغل می‌گیرند"},{"v":9,"t":"و کسانی هستند که یتیم را از پستان می‌ربایند و از فقیر گرو می‌گیرند."},{"v":10,"t":"پس ایشان بی‌لباس و برهنه راه می‌روند وبافه‌ها را برمی دارند و گرسنه می‌مانند."},{"v":11,"t":"دردروازه های آنها روغن می‌گیرند و چرخشت آنهارا پایمال می‌کنند و تشنه می‌مانند."},{"v":12,"t":"ازشهرآباد، نعره می‌زنند و جان مظلومان استغاثه می‌کند. اما خدا حماقت آنها را به نظر نمی آورد."},{"v":13,"t":"«و دیگرانند که از نور متمردند و راه آن رانمی دانند. و در طریق هایش سلوک نمی نمایند."},{"v":14,"t":"قاتل در صبح برمی خیزد و فقیر و مسکین رامی کشد. و در شب مثل دزد می‌شود."},{"v":15,"t":"چشم زناکار نیز برای شام انتظار می‌کشد و می‌گوید که چشمی مرا نخواهد دید، و بر روی خود پرده می‌کشد."},{"v":16,"t":"در تاریکی به خانه‌ها نقب می‌زنند ودر روز، خویشتن را پنهان می‌کنند و روشنایی رانمی دانند،"},{"v":17,"t":"زیرا صبح برای جمیع ایشان مثل سایه موت است، چونکه ترسهای سایه موت رامی دانند."},{"v":18,"t":"آنها بر روی آبها سبک‌اند و نصیب ایشان بر زمین ملعون است، و به راه تاکستان مراجعت نمی کنند."},{"v":19,"t":"چنانکه خشکی و گرمی آب برف را نابود می‌سازد، همچنین هاویه خطاکاران را."},{"v":20,"t":"رحم (مادرش ) او را فراموش می‌نماید و کرم، او را نوش می‌کند. و دیگر مذکورنخواهد شد، و شرارت مثل درخت بریده خواهدشد."},{"v":21,"t":"زن عاقر را که نمی زاید می‌بلعد و به زن بیوه احسان نمی نماید،"},{"v":22,"t":"و اما خدا جباران را به قوت خود محفوظ می‌دارد. برمی خیزند اگرچه امید زندگی ندارند،"},{"v":23,"t":"ایشان را اطمینان می‌بخشد و بر آن تکیه می‌نمایند، اما چشمان اوبر راههای ایشان است."},{"v":24,"t":"اندک زمانی بلندمی شوند، پس نیست می‌گردند و پست شده، مثل سایرین برده می‌شوند و مثل سر سنبله‌ها بریده می‌گردند،"},{"v":25,"t":"و اگر چنین نیست پس کیست که مراتکذیب نماید و کلام مرا ناچیز گرداند؟»"}]},"25":{"fa":[{"v":1,"t":"پس بلدد شوحی در جواب گفت:"},{"v":2,"t":"«سلطنت و هیبت از آن اوست وسلامتی را در مکان های بلند خود ایجاد می‌کند."},{"v":3,"t":"آیا افواج او شمرده می‌شود و کیست که نور اوبر وی طلوع نمی کند؟"},{"v":4,"t":"پس انسان چگونه نزد خدا عادل شمرده شود؟ و کسی‌که از زن زاییده شود، چگونه پاک باشد؟"},{"v":5,"t":"اینک ماه نیز روشنایی ندارد و ستارگان در نظر او پاک نیستند."},{"v":6,"t":"پس چندمرتبه زیاده انسان که مثل خزنده زمین و بنی آدم که مثل کرم می‌باشد.»"}]},"26":{"fa":[{"v":1,"t":"پس ایوب در جواب گفت:"},{"v":2,"t":"«شخص بی‌قوت را چگونه اعانت کردی؟ و بازوی ناتوان را چگونه نجات دادی؟"},{"v":3,"t":"شخص بی‌حکمت را چه نصیحت نمودی؟ وحقیقت امر را به فراوانی اعلام کردی!"},{"v":4,"t":"برای که سخنان را بیان کردی؟ و نفخه کیست که از توصادر شد؟"},{"v":5,"t":"ارواح مردگان می‌لرزند، زیر آبها وساکنان آنها."},{"v":6,"t":"هاویه به حضور او عریان است، وابدون را ستری نیست."},{"v":7,"t":"شمال را بر جو پهن می‌کند، و زمین را بر نیستی آویزان می‌سازد."},{"v":8,"t":"آبها را در ابرهای خود می‌بندد، پس ابر، زیرآنها چاک نمی شود."},{"v":9,"t":"روی تخت خود رامحجوب می‌سازد و ابرهای خویش را پیش آن می‌گستراند."},{"v":10,"t":"به اطراف سطح آبها حد می‌گذاردتا کران روشنایی و تاریکی."},{"v":11,"t":"ستونهای آسمان متزلزل می‌شود و از عتاب او حیران می‌ماند."},{"v":12,"t":"به قوت خود دریا را به تلاطم می‌آورد، و به فهم خویش رهب را خرد می‌کند."},{"v":13,"t":"به روح اوآسمانها زینت داده شد، و دست او مار تیز رو راسفت."},{"v":14,"t":"اینک اینها حواشی طریق های او است. و چه آواز آهسته‌ای درباره او می‌شنویم، لکن رعد جبروت او را کیست که بفهمد؟»"}]},"27":{"fa":[{"v":1,"t":"و ایوب دیگرباره مثل خود را آورده، گفت:"},{"v":2,"t":"«به حیات خدا که حق مرابرداشته و به قادرمطلق که جان مرا تلخ نموده است."},{"v":3,"t":"که مادامی که جانم در من باقی است ونفخه خدا در بینی من می‌باشد،"},{"v":4,"t":"یقین لبهایم به بی‌انصافی تکلم نخواهد کرد، و زبانم به فریب تنطق نخواهد نمود."},{"v":5,"t":"حاشا از من که شما راتصدیق نمایم، و تا بمیرم کاملیت خویش را ازخود دور نخواهم ساخت."},{"v":6,"t":"عدالت خود را قایم نگاه می‌دارم و آن را ترک نخواهم نمود، و دلم تازنده باشم، مرا مذمت نخواهد کرد."},{"v":7,"t":"دشمن من مثل شریر باشد، و مقاومت کنندگانم مثل خطاکاران."},{"v":8,"t":"زیرا امید شریر چیست هنگامی که خدا او را منقطع می‌سازد؟ و حینی که خدا جان اورا می‌گیرد؟"},{"v":9,"t":"آیا خدا فریاد او را خواهد شنید، هنگامی که مصیبت بر او عارض شود؟"},{"v":10,"t":"آیا درقادرمطلق تلذذ خواهد یافت، و در همه اوقات ازخدا مسالت خواهد نمود؟"},{"v":11,"t":"«شما را درباره دست خدا تعلیم خواهد دادو از اعمال قادرمطلق چیزی مخفی نخواهم داشت."},{"v":12,"t":"اینک جمیع شما این را ملاحظه کرده‌اید، پس چرا بالکل باطل شده‌اید."},{"v":13,"t":"این است نصیب مرد شریر از جانب خدا، و میراث ظالمان که آن را از قادرمطلق می‌یابند."},{"v":14,"t":"اگرفرزندانش بسیار شوند شمشیر برای ایشان است، و ذریت او از نان سیر نخواهند شد."},{"v":15,"t":"بازماندگان او از وبا دفن خواهند شد، و بیوه‌زنانش گریه نخواهند کرد."},{"v":16,"t":"اگر‌چه نقره را مثل غبار اندوخته کند، و لباس را مثل گل آماده سازد."},{"v":17,"t":"او آماده می‌کند لیکن مرد عادل آن را خواهد پوشید، وصالحان نقره او را تقسیم خواهند نمود."},{"v":18,"t":"خانه خود را مثل بید بنا می‌کند، و مثل سایبانی که دشتبان می‌سازد"},{"v":19,"t":"او دولتمند می‌خوابد اما دفن نخواهد شد. چشمان خود را می‌گشاید و نیست می‌باشد."},{"v":20,"t":"ترسها مثل آب او را فرو می‌گیرد، و گردباد او را در شب می‌رباید."},{"v":21,"t":"باد شرقی او رابرمی دارد و نابود می‌شود و او را از مکانش دورمی اندازد،"},{"v":22,"t":"زیرا (خدا) بر او تیر خواهدانداخت و شفقت نخواهد نمود. اگر‌چه اومی خواهد از دست وی فرار کرده، بگریزد."},{"v":23,"t":"مردم کفهای خود را بر او بهم می‌زنند و او را ازمکانش صفیر زده، بیرون می‌کنند."}]},"28":{"fa":[{"v":1,"t":"«یقین برای نقره معدنی است، و به جهت طلا جایی است که آن را قال می‌گذارند."},{"v":2,"t":"آهن از خاک گرفته می‌شود و مس ازسنگ گداخته می‌گردد."},{"v":3,"t":"مردم برای تاریکی حدمی گذارند و تا نهایت تمام تفحص می‌نمایند، تابه سنگهای ظلمت غلیظ و سایه موت."},{"v":4,"t":"کانی دور از ساکنان زمین می‌کنند، از راه گذریان فراموش می‌شوند و دور از مردمان آویخته شده، به هر طرف متحرک می‌گردند."},{"v":5,"t":"از زمین نان بیرون می‌آید، و ژرفیهایش مثل آتش سرنگون می‌شود."},{"v":6,"t":"سنگهایش مکان یاقوت کبود است. وشمشهای طلا دارد."},{"v":7,"t":"آن راه را هیچ مرغ شکاری نمی داند، و چشم شاهین آن را ندیده است،"},{"v":8,"t":"وجانوران درنده بر آن قدم نزده‌اند، و شیر غران برآن گذر نکرده."},{"v":9,"t":"دست خود را به سنگ خارا درازمی کنند، و کوهها را از بیخ برمی کنند."},{"v":10,"t":"نهرها ازصخره‌ها می‌کنند و چشم ایشان هر چیز نفیس رامی بیند."},{"v":11,"t":"نهرها را از تراوش می‌بندند وچیزهای پنهان شده را به روشنایی بیرون می‌آورند."},{"v":12,"t":"اما حکمت از کجا پیدا می‌شود؟ وجای فطانت کجا است؟"},{"v":13,"t":"انسان قیمت آن رانمی داند و در زمین زندگان پیدا نمی شود."},{"v":14,"t":"لجه می‌گوید که در من نیست، و دریا می‌گوید که نزدمن نمی باشد."},{"v":15,"t":"زر خالص به عوضش داده نمی شود و نقره برای قیمتش سنجیده نمی گردد."},{"v":16,"t":"به زر خالص اوفیر آن را قیمت نتوان کرد، و نه به جزع گرانبها و یاقوت کبود."},{"v":17,"t":"با طلا و آبگینه آن را برابر نتوان کرد، و زیورهای طلای خالص بدل آن نمی شود."},{"v":18,"t":"مرجان و بلور مذکورنمی شود و قیمت حکمت از لعل گرانتر است."},{"v":19,"t":"زبرجد حبش با آن مساوی نمی شود و به زرخالص سنجیده نمی گردد."},{"v":20,"t":"پس حکمت ازکجا می‌آید؟ و مکان فطانت کجا است؟"},{"v":21,"t":"ازچشم تمامی زندگان پنهان است، و از مرغان هوامخفی می‌باشد."},{"v":22,"t":"ابدون و موت می‌گویند که آوازه آن را به گوش خود شنیده‌ایم."},{"v":23,"t":"خدا راه آن را درک می‌کند و او مکانش را می‌داند."},{"v":24,"t":"زیراکه او تا کرانه های زمین می‌نگرد و آنچه را که زیرتمامی آسمان است می‌بیند."},{"v":25,"t":"تا وزن از برای بادقرار دهد، و آبها را به میزان بپیماید."},{"v":26,"t":"هنگامی که قانونی برای باران قرار داد، و راهی برای سهام رعد،"},{"v":27,"t":"آنگاه آن را دید و آن را بیان کرد. آن رامهیا ساخت و هم تفتیشش نمود."},{"v":28,"t":"و به انسان گفت: اینک ترس خداوند حکمت است، و ازبدی اجتناب نمودن، فطانت می‌باشد.»"}]},"29":{"fa":[{"v":1,"t":"و ایوب باز مثل خود را آورده، گفت:"},{"v":2,"t":"«کاش که من مثل ماههای پیش می‌بودم و مثل روزهایی که خدا مرا در آنها نگاه می‌داشت."},{"v":3,"t":"هنگامی که چراغ او بر سر من می‌تابید، و با نور او به تاریکی راه می‌رفتم."},{"v":4,"t":"چنانکه در روزهای کامرانی خود می‌بودم، هنگامی که سر خدا بر خیمه من می‌ماند."},{"v":5,"t":"وقتی که قادر مطلق هنوز با من می‌بود، و فرزندانم به اطراف من می‌بودند."},{"v":6,"t":"حینی که قدمهای خود را باکره می‌شستم و صخره، نهرهای روغن را برای من می ریخت."},{"v":7,"t":"چون به دروازه شهر بیرون می‌رفتم وکرسی خود را در چهار سوق حاضر می‌ساختم."},{"v":8,"t":"جوانان مرا دیده، خود را مخفی می‌ساختند، وپیران برخاسته، می‌ایستادند."},{"v":9,"t":"سروران از سخن‌گفتن بازمی ایستادند، و دست به دهان خودمی گذاشتند."},{"v":10,"t":"آواز شریفان ساکت می‌شد وزبان به کام ایشان می‌چسبید."},{"v":11,"t":"زیرا گوشی که مرا می‌شنید، مرا خوشحال می‌خواند و چشمی که مرا می‌دید، برایم شهادت می‌داد."},{"v":12,"t":"زیرافقیری که استغاثه می‌کرد او را می‌رهانیدم، ویتیمی که نیز معاون نداشت."},{"v":13,"t":"برکت شخصی که در هلاکت بود، به من می‌رسید و دل بیوه‌زن راخوش می‌ساختم."},{"v":14,"t":"عدالت را پوشیدم و مراملبس ساخت، و انصاف من مثل ردا و تاج بود."},{"v":15,"t":"من به جهت کوران چشم بودم، و به جهت لنگان پای."},{"v":16,"t":"برای مسکینان پدر بودم، و دعوایی را که نمی دانستم، تفحص می‌کردم."},{"v":17,"t":"دندانهای آسیای شریر را می‌شکستم و شکار را ازدندانهایش می‌ربودم."},{"v":18,"t":"«و می‌گفتم، در آشیانه خود جان خواهم سپرد و ایام خویش را مثل عنقا طویل خواهم ساخت."},{"v":19,"t":"ریشه من به سوی آبها کشیده خواهدگشت، و شبنم بر شاخه هایم ساکن خواهد شد."},{"v":20,"t":"جلال من در من تازه خواهد شد، و کمانم دردستم نو خواهد ماند."},{"v":21,"t":"مرا می‌شنیدند و انتظارمی کشیدند، و برای مشورت من ساکت می‌ماندند."},{"v":22,"t":"بعد از کلام من دیگر سخن نمی گفتند و قول من بر ایشان فرو می‌چکید."},{"v":23,"t":"و برای من مثل باران انتظار می‌کشیدند و دهان خویش را مثل باران آخرین باز می‌کردند."},{"v":24,"t":"اگر بر ایشان می‌خندیدم باور نمی کردند، و نور چهره مرا تاریک نمی ساختند."},{"v":25,"t":"راه را برای ایشان اختیار کرده، به ریاست می‌نشستم، و در میان لشکر، مثل پادشاه ساکن می‌بودم، و مثل کسی‌که نوحه‌گران را تسلی می‌بخشد."}]},"30":{"fa":[{"v":1,"t":"«و اما الان کسانی که از من خردسالترندبر من استهزا می‌کنند، که کراهت می‌داشتم از اینکه پدران ایشان را با سگان گله خود بگذارم."},{"v":2,"t":"قوت دستهای ایشان نیز برای من چه فایده داشت؟ کسانی که توانایی ایشان ضایع شده بود،"},{"v":3,"t":"از احتیاج و قحطی بی‌تاب شده، زمین خشک را در ظلمت خرابی و ویرانی می‌خاییدند."},{"v":4,"t":"خبازی را در میان بوته‌ها می‌چیدند، و ریشه شورگیاه نان ایشان بود."},{"v":5,"t":"از میان (مردمان ) رانده می‌شدند. از عقب ایشان مثل دزدان، هیاهومی کردند."},{"v":6,"t":"در گریوه های وادیها ساکن می‌شدند. در حفره های زمین و در صخره‌ها."},{"v":7,"t":"در میان بوته‌ها عرعر می‌کردند، زیر خارها با هم جمع می‌شدند."},{"v":8,"t":"ابنای احمقان و ابنای مردم بی‌نام، بیرون از زمین رانده می‌گردیدند."},{"v":9,"t":"و اما الان سرود ایشان شده‌ام و از برای ایشان ضرب‌المثل گردیده‌ام."},{"v":10,"t":"مرا مکروه داشته، از من دورمی شوند، و از آب دهان بر رویم انداختن، بازنمی ایستند."},{"v":11,"t":"چونکه زه را بر من باز کرده، مرامبتلا ساخت. پس لگام را پیش رویم رها کردند."},{"v":12,"t":"از طرف راست من انبوه عوام الناس برخاسته، پاهایم را از پیش در می‌برند، و راههای هلاکت خویش را بر من مهیا می‌سازند."},{"v":13,"t":"راه مرا خراب کرده، به اذیتم اقدام می‌نمایند، و خود معاونی ندارند."},{"v":14,"t":"گویا از ثلمه های وسیع می‌آیند، و ازمیان خرابه‌ها بر من هجوم می‌آورند."},{"v":15,"t":"ترسها برمن برگشته، آبروی مرا مثل باد تعاقب می‌کنند، و فیروزی من مثل ابر می‌گذرد."},{"v":16,"t":"و الان جانم بر من ریخته شده است، و روزهای مصیبت، مرا گرفتارنموده است."},{"v":17,"t":"شبانگاه استخوانهایم در اندرون من سفته می‌شود، و پیهایم آرام ندارد."},{"v":18,"t":"ازشدت سختی لباسم متغیر شده است، و مرا مثل گریبان پیراهنم تنگ می‌گیرد."},{"v":19,"t":"مرا در گل انداخته است، که مثل خاک و خاکستر گردیده‌ام."},{"v":20,"t":"«نزد تو تضرع می‌نمایم و مرا مستجاب نمی کنی، و برمی خیزم و بر من نظر نمی اندازی."},{"v":21,"t":"خویشتن را متبدل ساخته، بر من بیرحم شده‌ای، با قوت دست خود به من جفا می‌نمایی."},{"v":22,"t":"مرا به باد برداشته، برآن سوار گردانیدی، و مرادر تندباد پراکنده ساختی."},{"v":23,"t":"زیرا می‌دانم که مرابه موت باز خواهی گردانید، و به خانه‌ای که برای همه زندگان معین است."},{"v":24,"t":"یقین بر توده ویران دست خود را دراز نخواهد کرد، و چون کسی دربلا گرفتار شود، آیا به این سبب استغاثه نمی کند؟"},{"v":25,"t":"آیا برای هر مستمندی گریه نمی کردم، و دلم به جهت مسکین رنجیده نمی شد."},{"v":26,"t":"لکن چون امید نیکویی داشتم بدی آمد، و چون انتظار نورکشیدم ظلمت رسید."},{"v":27,"t":"احشایم می‌جوشد وآرام نمی گیرد، و روزهای مصیبت مرا درگرفته است."},{"v":28,"t":"ماتم‌کنان بی‌آفتاب گردش می‌کنم و درجماعت برخاسته، تضرع می‌نمایم."},{"v":29,"t":"برادرشغالان شده‌ام، و رفیق شترمرغ گردیده‌ام."},{"v":30,"t":"پوست من سیاه گشته، از من می‌ریزد، واستخوانهایم از حرارت سوخته گردیده است."},{"v":31,"t":"بربط من به نوحه گری مبدل شده و نای من به آواز گریه کنندگان."}]},"31":{"fa":[{"v":1,"t":"«با چشمان خود عهد بسته‌ام، پس چگونه بر دوشیزه‌ای نظر افکنم؟"},{"v":2,"t":"زیراقسمت خدا از اعلی چیست؟ و نصیب قادرمطلق، از اعلی علیین؟"},{"v":3,"t":"آیا آن برای شریران هلاکت نیست؟ و به جهت عاملان بدی مصیبت نی؟"},{"v":4,"t":"آیا او راههای مرا نمی بیند؟ و جمیع قدمهایم را نمی شمارد؟"},{"v":5,"t":"اگر با دروغ راه می‌رفتم یا پایهایم با فریب می‌شتابید،"},{"v":6,"t":"مرا به میزان عدالت بسنجد، تا خدا کاملیت مرا بداند."},{"v":7,"t":"اگرقدمهایم از طریق آواره گردیده، و قلبم در‌پی چشمانم رفته، و لکه‌ای به‌دستهایم چسبیده باشد،"},{"v":8,"t":"پس من کشت کنم و دیگری بخورد، ومحصول من از ریشه‌کنده شود."},{"v":9,"t":"اگر قلبم به زنی فریفته شده، یا نزد در همسایه خود در کمین نشسته باشم،"},{"v":10,"t":"پس زن من برای شخصی دیگرآسیا کند، و دیگران بر او خم شوند."},{"v":11,"t":"زیرا که آن قباحت می‌بود و تقصیری سزاوار حکم داوران."},{"v":12,"t":"چونکه این آتشی می‌بود که تا ابدون می‌سوزانید، و تمامی محصول مرا از ریشه می‌کند."},{"v":13,"t":"اگر دعوی بنده و کنیز خود را ردمی کردم، هنگامی که بر من مدعی می‌شدند."},{"v":14,"t":"پس چون خدا به ضد من برخیزد چه خواهم کرد؟ و هنگامی که تفتیش نماید به او چه جواب خواهم داد؟"},{"v":15,"t":"آیا آن کس که مرا در رحم آفریداو را نیز نیافرید؟ و آیا کس واحد، ما را در رحم نسرشت؟"},{"v":16,"t":"«اگر مراد مسکینان را از ایشان منع نموده باشم، و چشمان بیوه‌زنان را تار گردانیده،"},{"v":17,"t":"اگرلقمه خود را به تنهایی خورده باشم، و یتیم از آن تناول ننموده،"},{"v":18,"t":"و حال آنکه او از جوانیم با من مثل پدر پرورش می‌یافت، و از بطن مادرم بیوه‌زن را رهبری می‌نمودم."},{"v":19,"t":"اگر کسی را از برهنگی هلاک دیده باشم، و مسکین را بدون پوشش،"},{"v":20,"t":"اگر کمرهای او مرا برکت نداده باشد، و از پشم گوسفندان من گرم نشده،"},{"v":21,"t":"اگر دست خود را بر یتیم بلند کرده باشم، هنگامی که اعانت خود را دردروازه می‌دیدم،"},{"v":22,"t":"پس بازوی من از کتفم بیفتد، و ساعدم از قلم آن شکسته شود."},{"v":23,"t":"زیرا که هلاکت از خدا برای من ترس می‌بود و به‌سبب کبریایی او توانایی نداشتم."},{"v":24,"t":"اگر طلا را امیدخود می‌ساختم و به زر خالص می‌گفتم تو اعتمادمن هستی،"},{"v":25,"t":"اگر از فراوانی دولت خویش شادی می‌نمودم، و از اینکه دست من بسیار کسب نموده بود،"},{"v":26,"t":"اگر چون آفتاب می‌تابید بر آن نظرمی کردم و بر ماه، هنگامی که با درخشندگی سیرمی کرد."},{"v":27,"t":"و دل من خفیه فریفته می‌شد و دهانم دستم را می‌بوسید."},{"v":28,"t":"این نیز گناهی مستوجب قصاص می‌بود زیرا خدای متعال را منکرمی شدم."},{"v":29,"t":"اگر از مصیبت دشمن خود شادی می‌کردم یا حینی که بلا به او عارض می‌شد وجدمی نمودم،"},{"v":30,"t":"و حال آنکه زبان خود را از گناه ورزیدن بازداشته، بر جان او لعنت را سوال ننمودم."},{"v":31,"t":"اگر اهل خیمه من نمی گفتند: کیست که از گوشت او سیر نشده باشد،"},{"v":32,"t":"غریب درکوچه شب را به‌سر نمی برد و در خود را به روی مسافر می‌گشودم."},{"v":33,"t":"اگر مثل آدم، تقصیر خود رامی پوشانیدم و عصیان خویش را در سینه خودمخفی می‌ساختم،"},{"v":34,"t":"از این جهت که از انبوه کثیرمی ترسیدم و اهانت قبایل مرا هراسان می‌ساخت، پس ساکت مانده، از در خود بیرون نمی رفتم."},{"v":35,"t":"کاش کسی بود که مرا می‌شنید، اینک امضای من حاضر است. پس قادر مطلق مرا جواب دهد. و اینک کتابتی که مدعی من نوشته است."},{"v":36,"t":"یقین که آن را بر دوش خود برمی داشتم و مثل تاج برخود می‌بستم."},{"v":37,"t":"شماره قدمهای خود را برای اوبیان می‌کردم و مثل امیری به او تقرب می‌جستم."},{"v":38,"t":"اگر زمین من بر من فریاد می‌کرد و مرزهایش با هم گریه می‌کردند،"},{"v":39,"t":"اگر محصولاتش را بدون قیمت می‌خوردم و جان مالکانش را تلف می‌نمودم،"},{"v":40,"t":"پس خارها به عوض گندم وکرکاس به عوض جو بروید.» سخنان ایوب تمام شد."}]},"32":{"fa":[{"v":1,"t":"پس آن سه مرد از جواب دادن به ایوب باز ماندند چونکه او در نظر خود عادل بود."},{"v":2,"t":"آنگاه خشم الیهو ابن برکئیل بوزی که ازقبیله رام بود مشتعل شد، و غضبش بر ایوب افروخته گردید، از این جهت که خویشتن را ازخدا عادلتر می‌نمود."},{"v":3,"t":"و خشمش بر سه رفیق خود افروخته گردید، از این جهت که هر‌چندجواب نمی یافتند، اما ایوب را مجرم می‌شمردند."},{"v":4,"t":"و الیهو از سخن‌گفتن با ایوب درنگ نموده بود زیرا که ایشان در عمر، از وی بزرگتربودند."},{"v":5,"t":"اما چون الیهو دید که به زبان آن سه مردجوابی نیست، پس خشمش افروخته شد."},{"v":6,"t":"و الیهو ابن برکئیل بوزی به سخن آمده، گفت: «من در عمر صغیر هستم، و شما موسفید. بنابراین ترسیده، جرات نکردم که رای خود را برای شمابیان کنم."},{"v":7,"t":"و گفتم روزها سخن گوید، و کثرت سالها، حکمت را اعلام نماید."},{"v":8,"t":"لیکن در انسان روحی هست، و نفخه قادرمطلق، ایشان را فطانت می‌بخشد."},{"v":9,"t":"بزرگان نیستند که حکمت دارند، و نه پیران که انصاف را می‌فهمند."},{"v":10,"t":"بنابراین می‌گویم که مرا بشنو. و من نیز رای خود را بیان خواهم نمود."},{"v":11,"t":"اینک از سخن‌گفتن با شما درنگ نمودم، و براهین شما را گوش گرفتم. تا سخنان را کاوش گردید."},{"v":12,"t":"و من در شما تامل نمودم و اینک کسی از شما نبود که ایوب را ملزم سازد. یا سخنان او را جواب دهد."},{"v":13,"t":"مبادا بگویید که حکمت رادریافت نموده‌ایم، خدا او را مغلوب می‌سازد و نه انسان."},{"v":14,"t":"زیرا که سخنان خود را به ضد من ترتیب نداده است، و به سخنان شما او را جواب نخواهم داد."},{"v":15,"t":"ایشان حیران شده، دیگر جواب ندادند، وسخن از ایشان منقطع شد."},{"v":16,"t":"پس آیا من انتظاربکشم چونکه سخن نمی گویند؟ و ساکت شده، دیگر جواب نمی دهند؟"},{"v":17,"t":"پس من نیز از حصه خود جواب خواهم داد، و من نیز رای خود رابیان خواهم نمود."},{"v":18,"t":"زیرا که از سخنان، مملوهستم. و روح باطن من، مرا به تنگ می‌آورد."},{"v":19,"t":"اینک دل من مثل شرابی است که مفتوح نشده باشد، و مثل مشکهای تازه نزدیک است بترکد."},{"v":20,"t":"سخن خواهم راند تا راحت یابم و لبهای خودرا گشوده، جواب خواهم داد."},{"v":21,"t":"حاشا از من که طرفداری نمایم و به احدی کلام تملق‌آمیز گویم."},{"v":22,"t":"چونکه به گفتن سخنان تملق‌آمیز عارف نیستم. والا خالقم مرا به زودی خواهد برداشت."}]},"33":{"fa":[{"v":1,"t":"«لیکن‌ای ایوب، سخنان مرا استماع نما. و به تمامی کلام من گوش بگیر."},{"v":2,"t":"اینک الان دهان خود را گشودم، و زبانم در کامم متکلم شد."},{"v":3,"t":"کلام من موافق راستی قلبم خواهدبود. و لبهایم به معرفت خالص تنطق خواهدنمود."},{"v":4,"t":"روح خدا مرا آفریده، و نفخه قادرمطلق مرا زنده ساخته است."},{"v":5,"t":"اگر می‌توانی مرا جواب ده، و پیش روی من، کلام را ترتیب داده بایست."},{"v":6,"t":"اینک من مثل تو از خدا هستم. و من نیز از گل سرشته شده‌ام."},{"v":7,"t":"اینک هیبت من تو را نخواهدترسانید، و وقار من بر تو سنگین نخواهد شد."},{"v":8,"t":"«یقین در گوش من سخن گفتی و آواز کلام تو را شنیدم"},{"v":9,"t":"که گفتی من زکی و بی‌تقصیر هستم. من پاک هستم و در من گناهی نیست."},{"v":10,"t":"اینک او علتها برمن می‌جوید. و مرا دشمن خودمی شمارد."},{"v":11,"t":"پایهایم را در کنده می‌گذارد و همه راههایم را مراقبت می‌نماید."},{"v":12,"t":"هان در این امر توصادق نیستی. من تو را جواب می‌دهم، زیرا خدااز انسان بزرگتر است."},{"v":13,"t":"چرا با او معارضه می‌نمایی، از این جهت که از همه اعمال خوداطلاع نمی دهد؟"},{"v":14,"t":"زیرا خدا یک دفعه تکلم می‌کند، بلکه دو دفعه و انسان ملاحظه نمی نماید."},{"v":15,"t":"در خواب، در رویای شب، چون خواب سنگین بر انسان مستولی می‌شود، حینی که دربستر خود در خواب می‌باشد."},{"v":16,"t":"آنگاه گوشهای انسان را می‌گشاید و تادیب ایشان را ختم می‌سازد."},{"v":17,"t":"تا انسان را از اعمالش برگرداند وتکبر را از مردمان بپوشاند."},{"v":18,"t":"جان او را از حفره نگاه می‌دارد و حیات او را از هلاکت شمشیر."},{"v":19,"t":"بادرد در بستر خود سرزنش می‌یابد، و اضطراب دایمی در استخوانهای وی است."},{"v":20,"t":"پس جان اونان را مکروه می‌دارد و نفس او خوراک لطیف را."},{"v":21,"t":"گوشت او چنان فرسوده شد که دیده نمی شودو استخوانهای وی که دیده نمی شد برهنه گردیده است."},{"v":22,"t":"جان او به حفره نزدیک می‌شود و حیات او به هلاک کنندگان."},{"v":23,"t":"«اگر برای وی یکی به منزله هزار فرشته یامتوسطی باشد، تا آنچه را که برای انسان راست است به وی اعلان نماید،"},{"v":24,"t":"آنگاه بر او ترحم نموده، خواهد گفت: او را از فرو رفتن به هاویه برهان، من کفاره‌ای پیدا نموده‌ام."},{"v":25,"t":"گوشت او ازگوشت طفل لطیف تر خواهد شد. و به ایام جوانی خود خواهد برگشت."},{"v":26,"t":"نزد خدا دعا کرده، او رامستجاب خواهد فرمود، و روی او را با شادمانی خواهد دید. و عدالت انسان را به او رد خواهدنمود."},{"v":27,"t":"پس در میان مردمان سرود خوانده، خواهد گفت: گناه کردم و راستی را منحرف ساختم، و مکافات آن به من نرسید."},{"v":28,"t":"نفس مرا ازفرورفتن به هاویه فدیه داد، و جان من، نور رامشاهده می‌کند."},{"v":29,"t":"اینک همه این چیزها را خدابه عمل می‌آورد، دو دفعه و سه دفعه با انسان."},{"v":30,"t":"تا جان او را از هلاکت برگرداند و او را از نورزندگان، منور سازد."},{"v":31,"t":"‌ای ایوب متوجه شده، مرااستماع نما، و خاموش باش تا من سخن رانم."},{"v":32,"t":"اگر سخنی داری به من جواب بده، متکلم شوزیرا می‌خواهم تو را مبری سازم."},{"v":33,"t":"و اگر نه، تومرا بشنو. خاموش باش تا حکمت را به تو تعلیم دهم.»"}]},"34":{"fa":[{"v":1,"t":"پس الیهو تکلم نموده، گفت:"},{"v":2,"t":"«ای حکیمان سخنان مرا بشنوید، و‌ای عارفان، به من گوش گیرید."},{"v":3,"t":"زیرا گوش، سخنان را امتحان می‌کند، چنانکه کام، طعام را ذوق می‌نماید."},{"v":4,"t":"انصاف را برای خود اختیار کنیم، و درمیان خود نیکویی را بفهمیم."},{"v":5,"t":"چونکه ایوب گفته است که بی‌گناه هستم. و خدا داد مرا از من برداشته است."},{"v":6,"t":"هرچند انصاف با من است دروغگو شمرده شده‌ام، و هرچند بی‌تقصیرم، جراحت من علاج ناپذیر است."},{"v":7,"t":"کدام شخص مثل ایوب است که سخریه را مثل آب می‌نوشد"},{"v":8,"t":"که در رفاقت بدکاران سالک می‌شود، و با مردان شریر رفتار می‌نماید."},{"v":9,"t":"زیرا گفته است انسان رافایده‌ای نیست که رضامندی خدا را بجوید."},{"v":10,"t":"پس الان‌ای صاحبان فطانت مرا بشنوید، حاشااز خدا که بدی کند. و از قادرمطلق، که ظلم نماید."},{"v":11,"t":"زیرا که انسان را به حسب عملش مکافات می‌دهد، و بر هرکس موافق راهش می‌رساند."},{"v":12,"t":"وبه درستی که خدا بدی نمی کند، و قادر مطلق انصاف را منحرف نمی سازد."},{"v":13,"t":"کیست که زمین رابه او تفویض نموده، و کیست که تمامی ربع مسکون را به او سپرده باشد."},{"v":14,"t":"اگر او دل خود رابه وی مشغول سازد، اگر روح و نفخه خویش رانزد خود بازگیرد،"},{"v":15,"t":"تمامی بشر با هم هلاک می‌شوند و انسان به خاک راجع می‌گردد."},{"v":16,"t":"پس اگر فهم داری این را بشنو، و به آواز کلام من گوش ده."},{"v":17,"t":"آیا کسی‌که از انصاف نفرت دارد سلطنت خواهد نمود؟ و آیا عادل کبیر را به گناه اسنادمی دهی؟"},{"v":18,"t":"آیا به پادشاه گفته می‌شود که لئیم هستی، یا به نجیبان که شریر می‌باشید؟"},{"v":19,"t":"پس چگونه به آنکه امیران را طرفداری نمی نماید ودولتمند را بر فقیر ترجیح نمی دهد. زیرا که جمیع ایشان عمل دستهای وی‌اند."},{"v":20,"t":"درلحظه‌ای در نصف شب می‌میرند. قوم مشوش شده، می‌گذرند، و زورآوران بی‌واسطه دست انسان هلاک می‌شوند."},{"v":21,"t":"«زیرا چشمان او بر راههای انسان می‌باشد، و تمامی قدمهایش را می‌نگرد."},{"v":22,"t":"ظلمتی نیست و سایه موت نی، که خطاکاران خویشتن را درآن پنهان نمایند."},{"v":23,"t":"زیرا اندک زمانی بر احدی تامل نمی کند تا او پیش خدا به محاکمه بیاید."},{"v":24,"t":"زورآوران را بدون تفحص خرد می‌کند، ودیگران را به‌جای ایشان قرار می‌دهد."},{"v":25,"t":"هرآینه اعمال ایشان را تشخیص می‌نماید، و شبانگاه ایشان را واژگون می‌سازد تا هلاک شوند."},{"v":26,"t":"به‌جای شریران ایشان را می‌زند، در مکان نظرکنندگان."},{"v":27,"t":"از آن جهت که از متابعت اومنحرف شدند، و در همه طریقهای وی تامل ننمودند."},{"v":28,"t":"تا فریاد فقیر را به او برسانند، و اوفغان مسکینان را بشنود."},{"v":29,"t":"چون او آرامی دهدکیست که در اضطراب اندازد، و چون روی خودرا بپوشاند کیست که او را تواند دید. خواه به امتی خواه به انسانی مساوی است،"},{"v":30,"t":"تا مردمان فاجرسلطنت ننمایند و قوم را به دام گرفتار نسازند."},{"v":31,"t":"لیکن آیا کسی هست که به خدا بگوید: سزایافتم، دیگر عصیان نخواهم ورزید."},{"v":32,"t":"و آنچه راکه نمی بینم تو به من بیاموز، و اگر گناه کردم باردیگر نخواهم نمود."},{"v":33,"t":"آیا برحسب رای تو جزاداده، خواهد گفت: چونکه تو رد می‌کنی پس تواختیار کن و نه من. و آنچه صواب می‌دانی بگو."},{"v":34,"t":"صاحبان فطانت به من خواهند گفت، بلکه هرمرد حکیمی که مرا می‌شنود"},{"v":35,"t":"که ایوب بدون معرفت حرف می‌زند و کلام او از روی تعقل نیست."},{"v":36,"t":"کاش که ایوب تا به آخر آزموده شود، زیرا که مثل شریران جواب می‌دهد."},{"v":37,"t":"چونکه برگناه خود طغیان را مزید می‌کند و در میان مادستک می‌زند و به ضد خدا سخنان بسیارمی گوید.»"}]},"35":{"fa":[{"v":2,"t":"«آیا این را انصاف می‌شماری که گفتی من از خدا عادل تر هستم؟"},{"v":3,"t":"زیرا گفته‌ای برای توچه فایده خواهد شد، و به چه چیز بیشتر از گناهم منفعت خواهم یافت."},{"v":4,"t":"من تو را جواب می‌گویم ورفقایت را با تو."},{"v":5,"t":"به سوی آسمانها نظر کن و ببین وافلاک را ملاحظه نما که از تو بلندترند."},{"v":6,"t":"اگر گناه کردی به او چه رسانیدی؟ و اگر تقصیرهای تو بسیار شد برای وی چه کردی؟"},{"v":7,"t":"اگر بی‌گناه شدی به او چه بخشیدی؟ و یا از دست تو چه چیز را گرفته است؟"},{"v":8,"t":"شرارت تو به مردی چون تو (ضرر می‌رساند) و عدالت تو به بنی آدم (فایده می‌رساند)."},{"v":9,"t":"از کثرت ظلمها فریاد برمی آورند واز دست زورآوران استغاثه می‌کنند،"},{"v":10,"t":"و کسی نمی گوید که خدای آفریننده من کجا است که شبانگاه سرودها می‌بخشد"},{"v":11,"t":"و ما را از بهایم زمین تعلیم می‌دهد، و از پرندگان آسمان حکمت می‌بخشد."},{"v":12,"t":"پس به‌سبب تکبر شریران فریادمی کنند اما او اجابت نمی نماید،"},{"v":13,"t":"زیرا خدابطالت را نمی شنود و قادر مطلق برآن ملاحظه نمی فرماید."},{"v":14,"t":"هرچند می‌گویی که او رانمی بینم، لیکن دعوی در حضور وی است پس منتظر او باش."},{"v":15,"t":"و اما الان از این سبب که درغضب خویش مطالبه نمی کند و به کثرت گناه اعتنا نمی نماید،"},{"v":16,"t":"از این جهت ایوب دهان خودرا به بطالت می‌گشاید و بدون معرفت سخنان بسیار می‌گوید.»"}]},"36":{"fa":[{"v":1,"t":"و الیهو باز‌گفت:"},{"v":2,"t":"«برای من‌اندکی صبرکن تا تو را اعلام نمایم، زیرا از برای خدا هنوز سخنی باقی است."},{"v":3,"t":"علم خود را از دورخواهم آورد و به خالق خویش، عدالت راتوصیف خواهم نمود."},{"v":4,"t":"چونکه حقیقت کلام من دروغ نیست، و آنکه در علم کامل است نزد توحاضر است."},{"v":5,"t":"اینک خدا قدیر است و کسی رااهانت نمی کند و در قوت عقل قادر است."},{"v":6,"t":"شریررا زنده نگاه نمی دارد و داد مسکینان را می‌دهد."},{"v":7,"t":"چشمان خود را از عادلان برنمی گرداند، بلکه ایشان را با پادشاهان بر کرسی تا به ابد می‌نشاند، پس سرافراشته می‌شوند."},{"v":8,"t":"اما هرگاه به زنجیرهابسته شوند، و به بندهای مصیبت گرفتار گردند،"},{"v":9,"t":"آنگاه اعمال ایشان را به ایشان می‌نمایاند وتقصیرهای ایشان را از اینکه تکبر نموده‌اند،"},{"v":10,"t":"وگوشهای ایشان را برای تادیب باز می‌کند، و امرمی فرماید تا از گناه بازگشت نمایند."},{"v":11,"t":"پس اگربشنوند و او را عبادت نمایند، ایام خویش را درسعادت بسر خواهند برد، و سالهای خود را درشادمانی."},{"v":12,"t":"و اما اگر نشنوند از تیغ خواهند افتاد، و بدون معرفت، جان را خواهند سپرد."},{"v":13,"t":"اماآنانی که در دل، فاجرند غضب را ذخیره می‌نمایند، و چون ایشان را می‌بندد استغاثه نمی نمایند."},{"v":14,"t":"ایشان در عنفوان جوانی می‌میرندو حیات ایشان با فاسقان (تلف می‌شود)."},{"v":15,"t":"مصیبت کشان را به مصیبت ایشان نجات می‌بخشد و گوش ایشان را در تنگی باز می‌کند."},{"v":16,"t":"«پس تو را نیز از دهان مصیبت بیرون می‌آورد، در مکان وسیع که در آن تنگی نمی بود وزاد سفره تو از فربهی مملو می‌شد،"},{"v":17,"t":"و تو ازداوری شریر پر هستی، لیکن داوری و انصاف باهم ملتصقند."},{"v":18,"t":"باحذر باش مبادا خشم تو را به تعدی ببرد، و زیادتی کفاره تو را منحرف سازد."},{"v":19,"t":"آیا او دولت تو را به حساب خواهد آورد؟ نی، نه طلا و نه تمامی قوای توانگری را."},{"v":20,"t":"برای شب آرزومند مباش، که امت‌ها را از جای ایشان می‌برد."},{"v":21,"t":"با حذر باش که به گناه مایل نشوی، زیرا که تو آن را بر مصیبت ترجیح داده‌ای."},{"v":22,"t":"اینک خدا در قوت خود متعال می‌باشد. کیست که مثل او تعلیم بدهد؟"},{"v":23,"t":"کیست که طریق او را به او تفویض کرده باشد؟ و کیست که بگویدتو بی‌انصافی نموده‌ای؟"},{"v":24,"t":"به یاد داشته باش که اعمال او را تکبیر گویی که درباره آنها مردمان می‌سرایند."},{"v":25,"t":"جمیع آدمیان به آنها می‌نگرند. مردمان آنها را از دور مشاهده می‌نمایند."},{"v":26,"t":"اینک خدا متعال است و او را نمی شناسیم. و شماره سالهای او را تفحص نتوان کرد."},{"v":27,"t":"زیرا که قطره های آب را جذب می‌کند و آنها باران را ازبخارات آن می‌چکاند."},{"v":28,"t":"که ابرها آن را به شدت می‌ریزد و بر انسان به فراوانی می‌تراود."},{"v":29,"t":"آیاکیست که بفهمد ابرها چگونه پهن می‌شوند، یارعدهای خیمه او را بداند؟"},{"v":30,"t":"اینک نور خود رابر آن می‌گستراند. و عمق های دریا را می‌پوشاند."},{"v":31,"t":"زیرا که به واسطه آنها قوم‌ها را داوری می‌کند، و رزق را به فراوانی می‌بخشد."},{"v":32,"t":"دستهای خودرا با برق می‌پوشاند، و آن را بر هدف مامورمی سازد."},{"v":33,"t":"رعدش از او خبر می‌دهد و مواشی از برآمدن او اطلاع می‌دهند."}]},"37":{"fa":[{"v":1,"t":"«از این نیز دل می‌لرزد و از جای خودمتحرک می‌گردد."},{"v":2,"t":"گوش داده، صدای آواز او را بشنوید، و زمزمه‌ای را که از دهان وی صادر می‌شود،"},{"v":3,"t":"آن را در زیر تمامی آسمانهامی فرستد، و برق خویش را تا کرانهای زمین."},{"v":4,"t":"بعد از آن صدای غرش می‌کند و به آواز جلال خویش رعد می‌دهد و چون آوازش شنیده شدآنها را تاخیر نمی نماید."},{"v":5,"t":"خدا از آواز خودرعدهای عجیب می‌دهد. اعمال عظیمی که ماآنها را ادراک نمی کنیم به عمل می‌آورد،"},{"v":6,"t":"زیرابرف را می‌گوید: بر زمین بیفت. و همچنین بارش باران را و بارش بارانهای زورآور خویش را."},{"v":7,"t":"دست هر انسان را مختوم می‌سازد تا جمیع مردمان اعمال او را بدانند."},{"v":8,"t":"آنگاه وحوش به ماوای خود می‌روند و در بیشه های خویش آرام می‌گیرند."},{"v":9,"t":"از برجهای جنوب گردباد می‌آید و ازبرجهای شمال برودت."},{"v":10,"t":"از نفخه خدا یخ بسته می‌شود و سطح آبها منجمد می‌گردد."},{"v":11,"t":"ابرها رانیز به رطوبت سنگین می‌سازد و سحاب، برق خود را پراکنده می‌کند."},{"v":12,"t":"و آنها به دلالت او به هر سو منقلب می‌شوند تا هرآنچه به آنها امرفرماید بر روی تمامی ربع مسکون به عمل آورند."},{"v":13,"t":"خواه آنها را برای تادیب بفرستد یا به جهت زمین خود یا برای رحمت."},{"v":14,"t":"«ای ایوب این را استماع نما. بایست و دراعمال عجیب خدا تامل کن."},{"v":15,"t":"آیا مطلع هستی وقتی که خدا عزم خود را به آنها قرار می‌دهد وبرق، ابرهای خود را درخشان می‌سازد؟"},{"v":16,"t":"آیا تواز موازنه ابرها مطلع هستی؟ یا از اعمال عجیبه اوکه در علم، کامل است."},{"v":17,"t":"که چگونه رختهای توگرم می‌شود هنگامی که زمین از باد جنوبی ساکن می‌گردد."},{"v":18,"t":"آیا مثل او می‌توانی فلک رابگسترانی که مانند آینه ریخته شده مستحکم است؟"},{"v":19,"t":"ما را تعلیم بده که با وی چه توانیم گفت، زیرا به‌سبب تاریکی سخن نیکو نتوانیم آورد."},{"v":20,"t":"آیا چون سخن گویم به او خبر داده می‌شود یاانسان سخن گوید تا هلاک گردد."},{"v":21,"t":"و حال آفتاب را نمی توان دید هرچند در سپهر درخشان باشد تاباد وزیده آن را پاک کند."},{"v":22,"t":"درخشندگی طلایی از شمال می‌آید و نزد خدا جلال مهیب است."},{"v":23,"t":"قادر مطلق را ادراک نمی توانیم کرد، او در قوت وراستی عظیم است و در عدالت کبیر که بی‌انصافی نخواهد کرد."},{"v":24,"t":"لهذا مردمان از او می‌ترسند، امااو بر جمیع دانادلان نمی نگرد.»"}]},"38":{"fa":[{"v":1,"t":"و خداوند ایوب را از میان گردبادخطاب کرده، گفت:"},{"v":2,"t":"«کیست که مشورت را از سخنان بی‌علم تاریک می‌سازد؟"},{"v":3,"t":"الان کمر خود را مثل مرد ببند، زیرا که از توسوال می‌نمایم پس مرا اعلام نما."},{"v":4,"t":"وقتی که زمین را بنیاد نهادم کجا بودی؟ بیان کن اگر فهم داری."},{"v":5,"t":"کیست که آن را پیمایش نمود؟ اگر می‌دانی! وکیست که ریسمانکار را بر آن کشید؟"},{"v":6,"t":"پایه هایش بر چه چیز گذاشته شد؟ و کیست که سنگ زاویه‌اش را نهاد،"},{"v":7,"t":"هنگامی که ستارگان صبح باهم ترنم نمودند، و جمیع پسران خدا آوازشادمانی دادند؟"},{"v":8,"t":"و کیست که دریا را به درهامسدود ساخت، وقتی که به در جست و از رحم بیرون آمد؟"},{"v":9,"t":"وقتی که ابرها را لباس آن گردانیدم و تاریکی غلیظ را قنداقه آن ساختم."},{"v":10,"t":"و حدی برای آن قرار دادم و پشت بندها و درها تعیین نمودم."},{"v":11,"t":"و گفتم تا به اینجا بیا و تجاوز منما. و دراینجا امواج سرکش تو بازداشته شود."},{"v":12,"t":"«آیا تو از ابتدای عمر خود صبح را فرمان دادی، و فجر را به موضعش عارف گردانیدی؟"},{"v":13,"t":"تا کرانه های زمین را فرو‌گیرد و شریران از آن افشانده شوند."},{"v":14,"t":"مثل گل زیر خاتم مبدل می‌گردد. و همه‌چیز مثل لباس صورت می‌پذیرد."},{"v":15,"t":"و نور شریران از ایشان گرفته می‌شود، و بازوی بلند شکسته می‌گردد."},{"v":16,"t":"آیا به چشمه های دریا داخل شده، یا به عمقهای لجه رفته‌ای؟"},{"v":17,"t":"آیا درهای موت برای تو باز شده است؟ یا درهای سایه موت را دیده‌ای؟"},{"v":18,"t":"آیاپهنای زمین را ادراک کرده‌ای؟ خبر بده اگر این همه را می‌دانی."},{"v":19,"t":"راه مسکن نور کدام است، ومکان ظلمت کجا می‌باشد،"},{"v":20,"t":"تا آن را به حدودش برسانی، و راههای خانه او را درک نمایی؟"},{"v":21,"t":"البته می‌دانی، چونکه در آنوقت مولودشدی، و عدد روزهایت بسیار است!"},{"v":22,"t":"«آیا به مخزن های برف داخل شده، و خزینه های تگرگ را مشاهده نموده‌ای،"},{"v":23,"t":"که آنهارا به جهت وقت تنگی نگاه داشتم، به جهت روزمقاتله و جنگ؟"},{"v":24,"t":"به چه طریق روشنایی تقسیم می‌شود، و باد شرقی بر روی زمین منتشرمی گردد؟"},{"v":25,"t":"کیست که رودخانه‌ای برای سیل کند، یا طریقی به جهت صاعقه‌ها ساخت."},{"v":26,"t":"تا برزمینی که کسی در آن نیست ببارد و بر بیابانی که در آن آدمی نباشد،"},{"v":27,"t":"تا (زمین ) ویران و بایر راسیراب کند، و علفهای تازه را از آن برویاند؟"},{"v":28,"t":"آیا باران را پدری هست؟ یا کیست که قطرات شبنم را تولید نمود؟"},{"v":29,"t":"از رحم کیست که یخ بیرون آمد؟ و ژاله آسمان را کیست که تولیدنمود؟"},{"v":30,"t":"آبها مثل سنگ منجمد می‌شود، وسطح لجه یخ می‌بندد."},{"v":31,"t":"آیا عقد ثریا رامی بندی؟ یا بندهای جبار را می‌گشایی؟"},{"v":32,"t":"آیابرجهای منطقه البروج را در موسم آنها بیرون می‌آوری؟ و دب اکبر را با بنات او رهبری می‌نمایی؟"},{"v":33,"t":"آیا قانون های آسمان را می‌دانی؟ یا آن را بر زمین مسلط می‌گردانی؟"},{"v":34,"t":"آیا آوازخود را به ابرها می‌رسانی تا سیل آبها تو رابپوشاند؟"},{"v":35,"t":"آیا برقها را می‌فرستی تا روانه شوند، و به تو بگویند اینک حاضریم؟"},{"v":36,"t":"کیست که حکمت را در باطن نهاد یا فطانت را به دل بخشید؟"},{"v":37,"t":"کیست که با حکمت، ابرها رابشمارد؟ و کیست که مشکهای آسمان را بریزد؟"},{"v":38,"t":"چون غبار گل شده، جمع می‌شود و کلوخها باهم می‌چسبند."},{"v":39,"t":"آیا شکار را برای شیر ماده صید می‌کنی؟ و اشتهای شیر ژیان را سیرمی نمایی؟"},{"v":40,"t":"حینی که در ماوای خود خویشتن را جمع می‌کنند و در بیشه در کمین می‌نشینند؟"},{"v":41,"t":"کیست که غذا را برای غراب آماده می‌سازد، چون بچه هایش نزد خدا فریاد برمی آورند، و به‌سبب نبودن خوراک آواره می‌گردند؟"}]},"39":{"fa":[{"v":1,"t":"«آیا وقت زاییدن بز کوهی را می‌دانی؟ یا زمان وضع حمل آهو را نشان می‌دهی؟"},{"v":2,"t":"آیا ماههایی را که کامل می‌سازندحساب توانی کرد؟ یا زمان زاییدن آنهارامی دانی؟"},{"v":3,"t":"خم شده، بچه های خود را می‌زایند واز دردهای خود فارغ می‌شوند."},{"v":4,"t":"بچه های آنهاقوی شده، در بیابان نمو می‌کنند، می‌روند و نزدآنها برنمی گردند."},{"v":5,"t":"کیست که خر وحشی را رهاکرده، آزاد ساخت. و کیست که بندهای گورخر راباز نمود."},{"v":6,"t":"که من بیابان را خانه او ساختم، وشوره زار را مسکن او گردانیدم."},{"v":7,"t":"به غوغای شهراستهزاء می‌کند و خروش رمه بان را گوش نمی گیرد."},{"v":8,"t":"دایره کوهها چراگاه او است و هرگونه سبزه را می‌طلبد."},{"v":9,"t":"آیا گاو وحشی راضی شود که تو را خدمت نماید، یا نزد آخور تو منزل گیرد؟"},{"v":10,"t":"آیا گاو وحشی را به ریسمانش به شیار توانی بست؟ یا وادیها را از عقب تو مازو خواهد نمود؟"},{"v":11,"t":"آیا از اینکه قوتش عظیم است بر او اعتمادخواهی کرد؟ و کار خود را به او حواله خواهی نمود؟"},{"v":12,"t":"آیا براو توکل خواهی کرد که محصولت را باز آورد و آن را به خرمنگاهت جمع کند؟"},{"v":13,"t":"«بال شترمرغ به شادی متحرک می‌شود واما پر و بال او مثل لقلق نیست."},{"v":14,"t":"زیرا که تخمهای خود را به زمین وامی گذارد و بر روی خاک آنها را گرم می‌کند"},{"v":15,"t":"و فراموش می‌کند که پا آنها را می‌افشرد، و وحوش صحرا آنها راپایمال می‌کنند."},{"v":16,"t":"با بچه های خود سختی می کند که گویا از آن او نیستند، محنت او باطل است و متاسف نمی شود."},{"v":17,"t":"زیرا خدا او را ازحکمت محروم ساخته، و از فطانت او را نصیبی نداده است."},{"v":18,"t":"هنگامی که به بلندی پرواز می‌کنداسب و سوارش را استهزا می‌نماید."},{"v":19,"t":"«آیا تو اسب را قوت داده و گردن او را به یال ملبس گردانیده‌ای؟"},{"v":20,"t":"آیا او را مثل ملخ به جست وخیز آورده‌ای؟ خروش شیهه او مهیب است."},{"v":21,"t":"در وادی پا زده، از قوت خود وجدمی نماید و به مقابله مسلحان بیرون می‌رود."},{"v":22,"t":"برخوف استهزاء کرده، هراسان نمی شود، و از دم شمشیر برنمی گردد."},{"v":23,"t":"ترکش بر او چکچک می‌کند، و نیزه درخشنده و مزراق"},{"v":24,"t":"با خشم وغیض زمین را می‌نوردد. و چون کرنا صدا می‌کندنمی ایستد،"},{"v":25,"t":"وقتی که کرنا نواخته شود هه هه می‌گوید و جنگ را از دور استشمام می‌کند، وخروش سرداران و غوغا را."},{"v":26,"t":"آیا از حکمت توشاهین می‌پرد؟ و بالهای خود را بطرف جنوب پهن می‌کند؟"},{"v":27,"t":"آیا از فرمان تو عقاب صعودمی نماید و آشیانه خود را به‌جای بلند می‌سازد؟"},{"v":28,"t":"بر صخره ساکن شده، ماوا می‌سازد. بر صخره تیز و بر ملاذ منیع."},{"v":29,"t":"از آنجا خوراک خود را به نظر می‌آورد و چشمانش از دور می‌نگرد."},{"v":30,"t":"بچه هایش خون را می‌مکند و جایی که کشتگانند او آنجا است.»"}]},"40":{"fa":[{"v":2,"t":"«آیا مجادله کننده با قادرمطلق مخاصمه نماید؟ کسی‌که با خدا محاجه کند آن را جواب بدهد.»"},{"v":3,"t":"آنگاه ایوب خداوند را جواب داده، گفت:"},{"v":4,"t":"«اینک من حقیر هستم و به تو چه جواب دهم؟ دست خود را به دهانم گذاشته‌ام."},{"v":5,"t":"یک مرتبه گفتم و تکرار نخواهم کرد. بلکه دو مرتبه و نخواهم افزود.»"},{"v":6,"t":"پس خداوند ایوب را از گردباد خطاب کرد وگفت:"},{"v":7,"t":"«الان کمر خود را مثل مرد ببند. از توسوال می‌نمایم و مرا اعلام کن."},{"v":8,"t":"آیا داوری مرانیز باطل می‌نمایی؟ و مرا ملزم می‌سازی تاخویشتن را عادل بنمایی؟"},{"v":9,"t":"آیا تو را مثل خدابازویی هست؟ و به آواز مثل او رعد توانی کرد؟"},{"v":10,"t":"الان خویشتن را به جلال و عظمت زینت بده. و به عزت و شوکت ملبس ساز."},{"v":11,"t":"شدت غضب خود را بریز و به هرکه متکبر است نظر افکنده، اورا به زیر انداز."},{"v":12,"t":"بر هرکه متکبر است نظر کن و اورا ذلیل بساز. و شریران را در جای ایشان پایمال کن."},{"v":13,"t":"ایشان را با هم در خاک پنهان نما و رویهای ایشان را درجای مخفی محبوس کن."},{"v":14,"t":"آنگاه من نیز درباره تو اقرار خواهم کرد، که دست راستت تو را نجات تواند داد."},{"v":15,"t":"اینک بهیموت که او را باتو آفریده‌ام که علف را مثل گاو می‌خورد،"},{"v":16,"t":"همانا قوت او در کمرش می‌باشد، و توانایی وی در رگهای شکمش."},{"v":17,"t":"دم خود را مثل سروآزاد می‌جنباند. رگهای رانش بهم پیچیده است."},{"v":18,"t":"استخوانهایش مثل لوله های برنجین واعضایش مثل تیرهای آهنین است."},{"v":19,"t":"او افضل صنایع خدا است. آن که او را آفرید حربه‌اش را به او داده است."},{"v":20,"t":"به درستی که کوهها برایش علوفه می‌رویاند، که در آنها تمامی حیوانات صحرابازی می‌کنند"},{"v":21,"t":"زیر درختهای کنار می‌خوابد. در سایه نیزار و در خلاب."},{"v":22,"t":"درختهای کنار او را به سایه خود می‌پوشاند، و بیدهای نهر، وی رااحاطه می‌نماید."},{"v":23,"t":"اینک رودخانه طغیان می‌کند، لیکن او نمی ترسد و اگر‌چه اردن دردهانش ریخته شود ایمن خواهد بود."},{"v":24,"t":"آیا چون نگران است او را گرفتار توان کرد؟ یا بینی وی را باقلاب توان سفت؟"}]},"41":{"fa":[{"v":1,"t":"«آیا لویاتان را با قلاب توانی کشید؟ یازبانش را با ریسمان توانی فشرد؟"},{"v":2,"t":"آیادر بینی او مهار توانی کشید؟ یا چانه‌اش را باقلاب توانی سفت؟"},{"v":3,"t":"آیا او نزد تو تضرع زیادخواهد نمود؟ یا سخنان ملایم به تو خواهدگفت؟"},{"v":4,"t":"آیا با تو عهد خواهد بست یا او را برای بندگی دایمی خواهی گرفت؟"},{"v":5,"t":"آیا با او مثل گنجشک بازی توانی کرد؟ یا او را برای کنیزان خود توانی بست؟"},{"v":6,"t":"آیا جماعت (صیادان ) از اوداد و ستد خواهند کرد؟ یا او را در میان تاجران تقسیم خواهند نمود؟"},{"v":7,"t":"آیا پوست او را با نیزه هامملو توانی کرد؟ یا سرش را با خطافهای ماهی گیران؟"},{"v":8,"t":"اگر دست خود را بر او بگذاری جنگ را به یاد خواهی داشت و دیگر نخواهی کرد."},{"v":9,"t":"اینک امید به او باطل است. آیا از رویتش نیز آدمی به روی درافکنده نمی شود؟"},{"v":10,"t":"کسی اینقدر متهور نیست که او را برانگیزاند. پس کیست که در حضور من بایستد؟"},{"v":11,"t":"کیست که سبقت جسته، چیزی به من داده، تابه او رد نمایم؟ هرچه زیر آسمان است از آن من می‌باشد."},{"v":12,"t":"«درباره اعضایش خاموش نخواهم شد و ازجبروت و جمال ترکیب او خبر خواهم داد."},{"v":13,"t":"کیست که روی لباس او را باز تواند نمود؟ وکیست که در میان دو صف دندانش داخل شود؟"},{"v":14,"t":"کیست که درهای چهره‌اش را بگشاید؟ دایره دندانهایش هولناک است."},{"v":15,"t":"سپرهای زورآورش فخر او می‌باشد، با مهر محکم وصل شده است."},{"v":16,"t":"با یکدیگر چنان چسبیده‌اند که باد از میان آنهانمی گذرد."},{"v":17,"t":"با همدیگر چنان وصل شده‌اند و باهم ملتصقند که جدا نمی شوند."},{"v":18,"t":"از عطسه های او نور ساطع می‌گردد و چشمان او مثل پلکهای فجر است."},{"v":19,"t":"از دهانش مشعلها بیرون می‌آید وشعله های آتش برمی جهد."},{"v":20,"t":"از بینی های او دودبرمی آید مثل دیگ جوشنده و پاتیل."},{"v":21,"t":"از نفس او اخگرها افروخته می‌شود و از دهانش شعله بیرون می‌آید."},{"v":22,"t":"بر گردنش قوت نشیمن دارد، وهیبت پیش رویش رقص می‌نماید."},{"v":23,"t":"طبقات گوشت او بهم چسبیده است، و بر وی مستحکم است که متحرک نمی شود."},{"v":24,"t":"دلش مثل سنگ مستحکم است، و مانند سنگ زیرین آسیا محکم می‌باشد."},{"v":25,"t":"چون او برمی خیزد نیرومندان هراسان می‌شوند، و از خوف بی‌خود می‌گردند."},{"v":26,"t":"اگر شمشیر به او انداخته شود اثر نمی کند، و نه نیزه و نه مزراق و نه تیر."}]},"42":{"fa":[{"v":1,"t":"و ایوب خداوند را جواب داده، گفت:"},{"v":2,"t":"«می‌دانم که به هر چیز قادر هستی، وابدا قصد تو را منع نتوان نمود."},{"v":3,"t":"کیست که مشورت را بی‌علم مخفی می‌سازد. لکن من به آنچه نفهمیدم تکلم نمودم. به چیزهایی که فوق ازعقل من بود و نمی دانستم."},{"v":4,"t":"الان بشنو تا من سخن گویم. از تو سوال می‌نمایم مرا تعلیم بده."},{"v":5,"t":"ازشنیدن گوش درباره تو شنیده بودم لیکن الان چشم من تو را می‌بیند."},{"v":6,"t":"از این جهت از خویشتن کراهت دارم و در خاک و خاکستر توبه می‌نمایم.»"},{"v":7,"t":"و واقع شد بعد از اینکه خداوند این سخنان را به ایوب گفته بود که خداوند به الیفاز تیمانی فرمود: «خشم من بر تو و بر دو رفیقت افروخته شده، زیرا که درباره من آنچه راست است مثل بنده‌ام ایوب نگفتید."},{"v":8,"t":"پس حال هفت گوساله وهفت قوچ برای خود بگیرید و نزد بنده من ایوب رفته، قربانی سوختنی به جهت خویشتن بگذرانید و بنده‌ام ایوب به جهت شما دعا خواهدنمود، زیرا که او را مستجاب خواهم فرمود، مباداپاداش حماقت شما را به شما برسانم چونکه درباره من آنچه راست است مثل بنده‌ام ایوب نگفتید.»"},{"v":9,"t":"پس الیفاز تیمانی و بلدد شوحی و صوفرنعماتی رفته، به نوعی که خداوند به ایشان امر فرموده بود عمل نمودند و خداوند ایوب رامستجاب فرمود."},{"v":10,"t":"و چون ایوب برای اصحاب خود دعا کرد خداوند مصیبت او را دور ساخت وخداوند به ایوب دو چندان آنچه پیش داشته بودعطا فرمود."},{"v":11,"t":"و جمیع برادرانش و همه خواهرانش و تمامی آشنایان قدیمش نزد وی آمده، در خانه‌اش با وی نان خوردند و او را درباره تمامی مصیبتی که خداوند به او رسانیده بودتعزیت گفته، تسلی دادند و هرکس یک قسیطه وهرکس یک حلقه طلا به او داد."},{"v":12,"t":"و خداوند آخرایوب را بیشتر از اول او مبارک فرمود، چنانکه او را چهارده هزار گوسفند و شش هزار شتر و هزارجفت گاو و هزار الاغ ماده بود."},{"v":13,"t":"و او را هفت پسر و سه دختر بود."},{"v":14,"t":"و دختر اول را یمیمه ودوم را قصیعه و سوم را قرن هفوک نام نهاد."},{"v":15,"t":"و در تمامی زمین مثل دختران ایوب زنان نیکوصورت یافت نشدند و پدر ایشان، ایشان رادر میان برادرانشان ارثی داد."},{"v":16,"t":"و بعد از آن ایوب صد و چهل سال زندگانی نمود و پسران خود و پسران پسران خود را تا پشت چهارم دید."},{"v":17,"t":"پس ایوب پیر و سالخورده شده، وفات یافت."}]}});
